@@ -0,0 +1,84 @@
+codeunit 134276 "Purch. Jnl. Doc. Amount Decimals"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Currency] [Decimal Places]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        DocumentAmountErr: Label 'Document Amount should accept value with 3 decimal places. Expected %1, Actual %2';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocumentAmountAcceptsThreeDecimalPlaces()
+    var
+        PurchaseJournal: TestPage "Purchase Journal";
+        CurrencyCode: Code[10];
+        TestAmount: Decimal;
+    begin
+        // [FEATURE] [UI] [Document Amount]
+        // [SCENARIO] Document Amount field in Purchase Journal should accept values with 3 decimal places when using a currency with 3 decimal places (like TND)
+        Initialize();
+
+        // [GIVEN] A currency with 3 decimal places (similar to TND)
+        CurrencyCode := CreateCurrencyWithThreeDecimalPlaces();
+
+        // [GIVEN] Purchase Journal is opened
+        PurchaseJournal.OpenView();
+        PurchaseJournal.New();
+
+        // [GIVEN] Currency Code is set to the 3-decimal currency
+        PurchaseJournal."Currency Code".SetValue(CurrencyCode);
+
+        // [WHEN] Set Document Amount to a value with 3 decimal places (e.g., 1.234)
+        TestAmount := 1.234;
+        PurchaseJournal.DocumentAmount.SetValue(TestAmount);
+
+        // [THEN] The Document Amount is accepted and Amount field shows the correct value
+        Assert.AreEqual(
+            Format(-TestAmount),
+            PurchaseJournal.Amount.Value,
+            StrSubstNo(DocumentAmountErr, Format(-TestAmount), PurchaseJournal.Amount.Value));
+
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        GenJnlManagement: Codeunit GenJnlManagement;
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Purch. Jnl. Doc. Amount Decimals");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Purch. Jnl. Doc. Amount Decimals");
+
+        GenJnlManagement.SetJournalSimplePageModePreference(true, Page::"Purchase Journal");
+
+        isInitialized := true;
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Purch. Jnl. Doc. Amount Decimals");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(): Code[10]
+    var
+        Currency: Record Currency;
+        CurrencyCode: Code[10];
+    begin
+        // Create a currency similar to TND (Tunisian Dinar) which has 3 decimal places
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 1, 1);
+        Currency.Get(CurrencyCode);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+        exit(CurrencyCode);
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/ERMReminderDimension.Codeunit.al b/App/Layers/W1/Tests/ERM/ERMReminderDimension.Codeunit.al
