+++ b/App/Layers/W1/Tests/ERM/ERMReminderDimension.Codeunit.al
@@ -0,0 +1,202 @@
+codeunit 134999 "ERM Reminder Dimension"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        IsInitialized := false;
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryDimension: Codeunit "Library - Dimension";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    var
+        FeatureKey: Record "Feature Key";
+        FeatureKeyUpdateStatus: Record "Feature Data Update Status";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"ERM Reminder Dimension");
+        LibrarySetupStorage.Restore();
+        if FeatureKey.Get('ReminderTermsCommunicationTexts') then begin
+            FeatureKey.Enabled := FeatureKey.Enabled::None;
+            FeatureKey.Modify();
+        end;
+        if FeatureKeyUpdateStatus.Get('ReminderTermsCommunicationTexts', CompanyName()) then begin
+            FeatureKeyUpdateStatus."Feature Status" := FeatureKeyUpdateStatus."Feature Status"::Disabled;
+            FeatureKeyUpdateStatus.Modify();
+        end;
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"ERM Reminder Dimension");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+        IsInitialized := true;
+        Commit();
+
+        LibrarySetupStorage.SaveGeneralLedgerSetup();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"ERM Reminder Dimension");
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderCustLedgerEntryHasModifiedHeaderDimension()
+    var
+        ReminderLevel: Record "Reminder Level";
+        SalesHeader: Record "Sales Header";
+        Customer: Record Customer;
+        ReminderHeader: Record "Reminder Header";
+        ReminderTerms: Record "Reminder Terms";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        DimensionSetEntry: Record "Dimension Set Entry";
+        DimensionValue: array[2] of Record "Dimension Value";
+        IssuedReminderNo: Code[20];
+        GlobalDimCode: Code[20];
+    begin
+        // [SCENARIO] When a Reminder has its dimensions modified before being issued, 
+        // the Customer Ledger Entry should reflect the modified dimension from the Reminder Header,
+        // not the original dimension from the customer defaults.
+        Initialize();
+
+        // [GIVEN] Global Dimension 1 with two dimension values "DIM1" and "DIM2"
+        GlobalDimCode := LibraryERM.GetGlobalDimensionCode(1);
+        LibraryDimension.CreateDimensionValue(DimensionValue[1], GlobalDimCode);
+        LibraryDimension.CreateDimensionValue(DimensionValue[2], GlobalDimCode);
+
+        // [GIVEN] Customer "C" with Reminder Terms and Post Additional Fee = True
+        CreateReminderTerms(ReminderLevel, '');
+        ReminderTerms.Get(ReminderLevel."Reminder Terms Code");
+        ReminderTerms."Post Additional Fee" := true;
+        ReminderTerms.Modify(true);
+        Customer.Get(CreateCustomer(ReminderLevel."Reminder Terms Code", ''));
+
+        // [GIVEN] Customer "C" has default dimension with value "DIM1"
+        LibraryDimension.CreateDefaultDimensionCustomer(Customer."No.", GlobalDimCode, DimensionValue[1].Code);
+
+        // [GIVEN] Posted Sales Invoice for Customer "C"
+        CreateAndPostSalesInvoice(SalesHeader, Customer."No.");
+
+        // [GIVEN] Reminder is created and suggested for Customer "C"
+        ReminderHeader.Get(
+          CreateAndSuggestReminder(
+            SalesHeader."Sell-to Customer No.",
+            CalcDate('<1D>', CalcDate(ReminderLevel."Grace Period", SalesHeader."Due Date"))));
+
+        // [GIVEN] Reminder Header dimension is changed from "DIM1" to "DIM2"
+        ReminderHeader.Validate("Shortcut Dimension 1 Code", DimensionValue[2].Code);
+        ReminderHeader.Modify(true);
+
+        // [WHEN] Reminder is issued
+        IssuedReminderNo := IssueReminderAndGetIssuedNo(ReminderHeader."No.");
+
+        // [THEN] Customer Ledger Entry for the Reminder contains the modified dimension "DIM2"
+        CustLedgerEntry.SetRange("Document Type", CustLedgerEntry."Document Type"::Reminder);
+        CustLedgerEntry.SetRange("Document No.", IssuedReminderNo);
+        CustLedgerEntry.SetRange("Customer No.", Customer."No.");
+        CustLedgerEntry.FindFirst();
+
+        DimensionSetEntry.Get(CustLedgerEntry."Dimension Set ID", GlobalDimCode);
+        Assert.AreEqual(
+            DimensionValue[2].Code,
+            DimensionSetEntry."Dimension Value Code",
+            'Customer Ledger Entry should have the modified dimension from Reminder Header');
+    end;
+
+    local procedure CreateAndPostSalesInvoice(var SalesHeader: Record "Sales Header"; CustomerNo: Code[20])
+    var
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+    begin
+        LibraryInventory.CreateItemWithUnitPriceAndUnitCost(
+          Item, LibraryRandom.RandDec(1000, 2), LibraryRandom.RandDec(1000, 2));
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, CustomerNo);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandInt(10));
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+    end;
+
+    local procedure CreateCustomer(ReminderTermsCode: Code[10]; CurrencyCode: Code[10]): Code[20]
+    var
+        Customer: Record Customer;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Currency Code", CurrencyCode);
+        Customer.Validate("Reminder Terms Code", ReminderTermsCode);
+        Customer.Modify(true);
+        exit(Customer."No.");
+    end;
+
+    local procedure CreateReminderTerms(var ReminderLevel: Record "Reminder Level"; CurrencyCode: Code[10]): Code[10]
+    var
+        ReminderTerms: Record "Reminder Terms";
+    begin
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+        if CurrencyCode <> '' then
+            ModifyCurrencyOnReminderLevel(ReminderTerms.Code, ReminderLevel."Additional Fee (LCY)", CurrencyCode);
+        exit(ReminderTerms.Code);
+    end;
+
+    local procedure CreateReminderLevel(var ReminderLevel: Record "Reminder Level"; ReminderTermsCode: Code[10])
+    begin
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTermsCode);
+        Evaluate(ReminderLevel."Grace Period", '<' + Format(LibraryRandom.RandInt(5)) + 'M>');
+        ReminderLevel.Validate("Additional Fee (LCY)", LibraryRandom.RandInt(10));
+        ReminderLevel.Modify(true);
+    end;
+
+    local procedure CreateAndSuggestReminder(CustomerNo: Code[20]; DocumentDate: Date): Code[20]
+    var
+        ReminderHeader: Record "Reminder Header";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        CustLedgEntryLineFeeOn: Record "Cust. Ledger Entry";
+        ReminderMake: Codeunit "Reminder-Make";
+    begin
+        LibraryERM.CreateReminderHeader(ReminderHeader);
+        ReminderHeader.Validate("Customer No.", CustomerNo);
+        ReminderHeader.Validate("Document Date", DocumentDate);
+        ReminderHeader.Modify(true);
+
+        ReminderMake.SuggestLines(ReminderHeader, CustLedgerEntry, true, false, CustLedgEntryLineFeeOn);
+        ReminderMake.Code();
+        exit(ReminderHeader."No.");
+    end;
+
+    local procedure IssueReminder(ReminderHeader: Record "Reminder Header")
+    var
+        ReminderIssue: Codeunit "Reminder-Issue";
+    begin
+        ReminderIssue.Set(ReminderHeader, false, ReminderHeader."Document Date");
+        LibraryERM.RunReminderIssue(ReminderIssue);
+    end;
+
+    local procedure IssueReminderAndGetIssuedNo(ReminderNo: Code[20]) IssuedReminderNo: Code[20]
+    var
+        ReminderHeader: Record "Reminder Header";
+        NoSeries: Codeunit "No. Series";
+    begin
+        ReminderHeader.Get(ReminderNo);
+        IssuedReminderNo := NoSeries.PeekNextNo(ReminderHeader."Issuing No. Series");
+        IssueReminder(ReminderHeader);
+    end;
+
+    local procedure ModifyCurrencyOnReminderLevel(ReminderTermsCode: Code[10]; AdditionalFee: Decimal; CurrencyCode: Code[10])
+    var
+        CurrencyForReminderLevel: Record "Currency for Reminder Level";
+    begin
+        LibraryERM.CreateCurrencyForReminderLevel(CurrencyForReminderLevel, ReminderTermsCode, CurrencyCode);
+        CurrencyForReminderLevel.Validate("Additional Fee", AdditionalFee);
+        CurrencyForReminderLevel.Modify(true);
+    end;
+}

diff --git a/App/Layers/W1/Tests/Job/JobJournal.Codeunit.al b/App/Layers/W1/Tests/Job/JobJournal.Codeunit.al
index e427075e..6654b14e 100644
--- a/App/Layers/W1/Tests/Job/JobJournal.Codeunit.al
+++ b/App/Layers/W1/Tests/Job/JobJournal.Codeunit.al
@@ -2938,6 +2938,58 @@ codeunit 136305 "Job Journal"
         Assert.AreNotEqual(GenJournalLine."Job Total Cost (LCY)", PreviousProjectTotalCostLCY, ProjectTotalCostErr);
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJnlVariableMethodRetainsUnitCostAndPrice()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Journal]
+        // [SCENARIO] Posting a recurring job journal with Variable method should retain Unit Cost and Unit Price for next posting
+
+        // [GIVEN] A recurring job journal template
+        Initialize();
+        CreateRecurringJobJournalTemplateAndBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A job with a job task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] A resource with Unit Cost and Unit Price
+        LibraryResource.CreateResourceNew(Resource);
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A recurring job journal line with Variable recurring method
+        CreateRecurringJobJournalLine(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, Resource."No.", JobJournalLine."Recurring Method"::Variable);
+        ExpectedUnitCost := JobJournalLine."Unit Cost";
+        ExpectedUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Post the recurring job journal
+        Codeunit.Run(Codeunit::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The journal line should retain Unit Cost and Unit Price after posting
+        JobJournalLine.Find();
+        Assert.AreEqual(
+            ExpectedUnitCost, JobJournalLine."Unit Cost",
+            StrSubstNo(IncorrectFieldValueErr, JobJournalLine.FieldCaption("Unit Cost")));
+        Assert.AreEqual(
+            ExpectedUnitPrice, JobJournalLine."Unit Price",
+            StrSubstNo(IncorrectFieldValueErr, JobJournalLine.FieldCaption("Unit Price")));
+        // [THEN] Quantity should be zeroed out (Variable method behavior)
+        Assert.AreEqual(0, JobJournalLine.Quantity, StrSubstNo(IncorrectFieldValueErr, JobJournalLine.FieldCaption(Quantity)));
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
@@ -3290,6 +3342,39 @@ codeunit 136305 "Job Journal"
         JobJournalLine.Modify(true);
     end;

+    local procedure CreateRecurringJobJournalTemplateAndBatch(var JobJournalTemplate: Record "Job Journal Template"; var JobJournalBatch: Record "Job Journal Batch")
+    begin
+        JobJournalTemplate.Init();
+        JobJournalTemplate.Validate(Name, LibraryUtility.GenerateGUID());
+        JobJournalTemplate.Validate(Recurring, true);
+        JobJournalTemplate.Insert(true);
+
+        JobJournalBatch.Init();
+        JobJournalBatch.Validate("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalBatch.Validate(Name, LibraryUtility.GenerateGUID());
+        JobJournalBatch.Insert(true);
