@@ -0,0 +1,166 @@
+codeunit 135303 "Item Charge Sales Return Order"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Sales] [Return Order] [Item Charge]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure ItemChargeOnSalesReturnOrderWithDefaultQtyToShipBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        Customer: Record Customer;
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineCharge: Record "Sales Line";
+        ItemChargeAssignmentSales: Record "Item Charge Assignment (Sales)";
+        SalesReturnHeader: Record "Sales Header";
+        SalesReturnLine: Record "Sales Line";
+        PostedInvoiceNo: Code[20];
+    begin
+        // [SCENARIO] Item Charge can be pulled into Sales Return Order when Default Qty. to Ship is set to 'Blank' on Sales & Receivables Setup
+        // [GIVEN] "Default Quantity to Ship" is set to "Blank" in Sales & Receivables Setup
+        Initialize();
+        UpdateDefaultQtyToShip(SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+
+        // [GIVEN] A Sales Order with an Item line (Qty: 25) and an Item Charge line (Qty: 25)
+        LibrarySales.CreateCustomer(Customer);
+        LibraryInventory.CreateItem(Item);
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(10, 30));
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(10, 100, 2));
+        SalesLine.Validate("Qty. to Ship", SalesLine.Quantity);
+        SalesLine.Validate("Qty. to Invoice", SalesLine.Quantity);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Item Charge line is assigned to the Item line
+        LibrarySales.CreateSalesLine(
+            SalesLineCharge, SalesHeader, SalesLineCharge.Type::"Charge (Item)",
+            LibraryInventory.CreateItemChargeNo(), SalesLine.Quantity);
+        SalesLineCharge.Validate("Unit Price", LibraryRandom.RandDecInRange(1, 10, 2));
+        SalesLineCharge.Validate("Qty. to Ship", SalesLineCharge.Quantity);
+        SalesLineCharge.Validate("Qty. to Invoice", SalesLineCharge.Quantity);
+        SalesLineCharge.Modify(true);
+
+        CreateItemChargeAssignment(
+            ItemChargeAssignmentSales, SalesLineCharge, SalesHeader."Document Type",
+            SalesHeader."No.", SalesLine."Line No.", Item."No.", SalesLineCharge.Quantity);
+
+        // [GIVEN] Sales Order is posted (Ship and Invoice)
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] A Sales Return Order is created for the same customer
+        LibrarySales.CreateSalesHeader(SalesReturnHeader, SalesReturnHeader."Document Type"::"Return Order", Customer."No.");
+
+        // [WHEN] Get Posted Document Lines to Reverse is invoked (selecting Posted Invoices)
+        LibraryVariableStorage.Enqueue(PostedInvoiceNo);
+        SalesReturnHeader.GetPstdDocLinesToReverse();
+
+        // [THEN] No error occurs and both Item and Item Charge lines are copied to the Sales Return Order
+        SalesReturnLine.SetRange("Document Type", SalesReturnHeader."Document Type");
+        SalesReturnLine.SetRange("Document No.", SalesReturnHeader."No.");
+        SalesReturnLine.SetRange(Type, SalesReturnLine.Type::Item);
+        Assert.RecordIsNotEmpty(SalesReturnLine);
+
+        SalesReturnLine.SetRange(Type, SalesReturnLine.Type::"Charge (Item)");
+        Assert.RecordIsNotEmpty(SalesReturnLine);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Charge Sales Return Order");
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then begin
+            LibrarySetupStorage.Restore();
+            exit;
+        end;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Charge Sales Return Order");
+        LibrarySetupStorage.SaveSalesSetup();
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Charge Sales Return Order");
+    end;
+
+    local procedure UpdateDefaultQtyToShip(NewDefaultQtyToShip: Option)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Default Quantity to Ship", NewDefaultQtyToShip);
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateItemChargeAssignment(var ItemChargeAssignmentSales: Record "Item Charge Assignment (Sales)"; SalesLineCharge: Record "Sales Line"; DocType: Enum "Sales Document Type"; DocNo: Code[20]; ApplyToDocLineNo: Integer; ItemNo: Code[20]; QtyToAssign: Decimal)
+    var
+        RecRef: RecordRef;
+    begin
+        Clear(ItemChargeAssignmentSales);
+        ItemChargeAssignmentSales.Init();
+        ItemChargeAssignmentSales."Document Type" := SalesLineCharge."Document Type";
+        ItemChargeAssignmentSales."Document No." := SalesLineCharge."Document No.";
+        ItemChargeAssignmentSales."Document Line No." := SalesLineCharge."Line No.";
+        ItemChargeAssignmentSales."Item Charge No." := SalesLineCharge."No.";
+        ItemChargeAssignmentSales."Unit Cost" := SalesLineCharge."Unit Price";
+
+        RecRef.GetTable(ItemChargeAssignmentSales);
+        ItemChargeAssignmentSales."Line No." := GetNextLineNo(RecRef, ItemChargeAssignmentSales.FieldNo("Line No."));
+
+        ItemChargeAssignmentSales."Applies-to Doc. Type" := DocType;
+        ItemChargeAssignmentSales."Applies-to Doc. No." := DocNo;
+        ItemChargeAssignmentSales."Applies-to Doc. Line No." := ApplyToDocLineNo;
+        ItemChargeAssignmentSales."Item No." := ItemNo;
+        ItemChargeAssignmentSales.Insert(true);
+
+        ItemChargeAssignmentSales.Validate("Qty. to Assign", QtyToAssign);
+        ItemChargeAssignmentSales.Modify(true);
+    end;
+
+    local procedure GetNextLineNo(RecRef: RecordRef; FieldNo: Integer): Integer
+    var
+        LastRecRef: RecordRef;
+        FieldRef: FieldRef;
+    begin
+        LastRecRef := RecRef.Duplicate();
+        LastRecRef.Reset();
+        FieldRef := LastRecRef.Field(FieldNo);
+        LastRecRef.SetCurrentKey(FieldRef.Name);
+        if LastRecRef.FindLast() then begin
+            FieldRef := LastRecRef.Field(FieldNo);
+            exit(FieldRef.Value() + 10000);
+        end;
+        exit(10000);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    var
+        PostedInvoiceNo: Variant;
+    begin
+        // Select Posted Invoices and filter to specific invoice
+        LibraryVariableStorage.Dequeue(PostedInvoiceNo);
+        PostedSalesDocumentLines.PostedInvoices.FILTER.SetFilter("No.", PostedInvoiceNo);
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
+}

