+    [HandlerFunctions('ConfirmHandler')]
+    [Scope('OnPrem')]
+    procedure RegisterPutAwayWithBreakbulkFilterRegistersAllLines()
+    var
+        Location: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        WarehouseReceiptLine: Record "Warehouse Receipt Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        RegisteredWhseActivityLine: Record "Registered Whse. Activity Line";
+        WarehousePutAway: TestPage "Warehouse Put-away";
+        QtyPerUOM: Decimal;
+        PurchQty: Decimal;
+        TotalLinesBeforeRegister: Integer;
+    begin
+        // [FEATURE] [Put-Away] [Breakbulk]
+        // [SCENARIO] When registering a Put-away with Breakbulk Filter enabled, all put-away lines should be registered (not just visible ones).
+        // Bug: Previously, when Break Bulk Filter = Yes was set and put-away was registered, only the non-breakbulk lines were registered.
+        Initialize();
+        QtyPerUOM := LibraryRandom.RandIntInRange(10, 20);
+        PurchQty := LibraryRandom.RandIntInRange(5, 10);
+
+        // [GIVEN] Full WMS location "L" with Allow Breakbulk = FALSE (forces breakbulk lines to be created during put-away).
+        LibraryWarehouse.CreateFullWMSLocation(Location, 1);
+        Location.Validate("Allow Breakbulk", false);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX". "BOX" contains "X" units of "PCS".
+        // [GIVEN] Put-away Unit of Measure Code in the item is "PCS" (base UOM), different from purchase UOM "BOX".
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        UpdateItemUOM(Item, ItemUnitOfMeasure.Code, '', Item."Base Unit of Measure");
+
+        // [GIVEN] Create and release Purchase Order for "Y" units of "BOX" in location "L".
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, '');
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", PurchQty);
+        PurchaseLine.Validate("Location Code", Location.Code);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.ReleasePurchaseDocument(PurchaseHeader);
+
+        // [GIVEN] Posted warehouse receipt from the purchase order, which creates put-away with breakbulk lines.
+        LibraryWarehouse.CreateWhseReceiptFromPO(PurchaseHeader);
+        FindWarehouseReceiptLine(WarehouseReceiptLine, WarehouseReceiptLine."Source Document"::"Purchase Order", PurchaseHeader."No.");
+        PostWarehouseReceipt(WarehouseReceiptLine."No.");
+
+        // [GIVEN] Find the created Put-away and count total lines (including breakbulk lines).
+        FindWarehouseActivityLine(WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Purchase Order", PurchaseHeader."No.",
+          WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityHeader.Type);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        TotalLinesBeforeRegister := WarehouseActivityLine.Count();
+
+        // [GIVEN] Set Breakbulk Filter = Yes on the Warehouse Activity Header.
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Open the Warehouse Put-away page with Breakbulk Filter enabled and invoke Register Put-away.
+        WarehousePutAway.OpenEdit();
+        WarehousePutAway.FILTER.SetFilter("No.", WarehouseActivityHeader."No.");
+        WarehousePutAway.WhseActivityLines.First();
+        WarehousePutAway."&Register Put-away".Invoke();
+        WarehousePutAway.Close();
+
+        // [THEN] All put-away lines should be registered (the Put-away should no longer exist).
+        Assert.IsFalse(WarehouseActivityHeader.Get(WarehouseActivityHeader.Type, WarehouseActivityHeader."No."),
+            'Put-away should be deleted after successful registration');
+
+        // [THEN] Verify that the number of registered lines equals the total lines before registration.
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        Assert.AreEqual(TotalLinesBeforeRegister, RegisteredWhseActivityLine.Count(), AllLinesNotRegisteredErr);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Put-away Breakbulk Filter");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Put-away Breakbulk Filter");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Put-away Breakbulk Filter");
+    end;
+
+    local procedure CreateItemUnitOfMeasure(var ItemUnitOfMeasure: Record "Item Unit of Measure"; ItemNo: Code[20]; QtyPerUnitOfMeasure: Decimal)
+    begin
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, ItemNo, QtyPerUnitOfMeasure);
+    end;
+
+    local procedure UpdateItemUOM(var Item: Record Item; PurchUnitOfMeasure: Code[10]; SalesUnitOfMeasure: Code[10]; PutAwayUnitOfMeasureCode: Code[10])
+    begin
+        if PurchUnitOfMeasure <> '' then
+            Item.Validate("Purch. Unit of Measure", PurchUnitOfMeasure);
+        if SalesUnitOfMeasure <> '' then
+            Item.Validate("Sales Unit of Measure", SalesUnitOfMeasure);
+        if PutAwayUnitOfMeasureCode <> '' then
+            Item.Validate("Put-away Unit of Measure Code", PutAwayUnitOfMeasureCode);
+        Item.Modify(true);
+    end;
+
+    local procedure FindWarehouseReceiptLine(var WarehouseReceiptLine: Record "Warehouse Receipt Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20])
+    begin
+        WarehouseReceiptLine.SetRange("Source Document", SourceDocument);
+        WarehouseReceiptLine.SetRange("Source No.", SourceNo);
+        WarehouseReceiptLine.FindFirst();
+    end;
+
+    local procedure PostWarehouseReceipt(No: Code[20])
+    var
+        WarehouseReceiptHeader: Record "Warehouse Receipt Header";
+    begin
+        WarehouseReceiptHeader.Get(No);
+        LibraryWarehouse.PostWhseReceipt(WarehouseReceiptHeader);
+    end;
+
+    local procedure FindWarehouseActivityLine(var WarehouseActivityLine: Record "Warehouse Activity Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20]; ActivityType: Enum "Warehouse Activity Type")
+    begin
+        WarehouseActivityLine.SetRange("Source Document", SourceDocument);
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.FindFirst();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandler(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

