+        // [GIVEN] Create item with Reserve = Optional.
+        LibraryInventory.CreateItem(ItemOptional);
+        ItemOptional.Validate(Reserve, ItemOptional.Reserve::Optional);
+        ItemOptional.Modify(true);
+        ItemList.Add(ItemOptional."No.");
+
+        // [GIVEN] Create item with Reserve = Always.
