+    [Test]
+    [Scope('OnPrem')]
+    procedure MfgOverheadIsCorrectWithMultipleProdOrderLines()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        TotalExpMatCost: Decimal;
+        TotalExpMfgOvhdCost: Decimal;
+        UnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        QtyPerLine: Decimal;
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [Statistics]
+        // [SCENARIO] Manufacturing overhead is correctly calculated when production order has multiple lines
+
+        // [GIVEN] A raw material item with Unit Cost = 100
+        Initialize();
+        UnitCost := 100;
+        IndirectCostPct := 10;
+        QtyPerLine := 10;
+
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", UnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] A Production BOM with 1 unit of raw material
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, RawItem."No.", 1);
+
+        // [GIVEN] A finished good item with Indirect Cost % = 10
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [GIVEN] A production order with two lines, each with Qty 10 (total 20)
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::"Firm Planned",
+          ProductionOrder."Source Type"::Item, FGItem."No.", 0);
+
+        LibraryManufacturing.CreateProdOrderLine(
+          ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+          FGItem."No.", '', '', QtyPerLine);
+
+        LibraryManufacturing.CreateProdOrderLine(
+          ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+          FGItem."No.", '', '', QtyPerLine);
+
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs for each production order line
+        TotalExpMatCost := 0;
+        TotalExpMfgOvhdCost := 0;
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindSet();
+        repeat
+            ExpMatCost := 0;
+            ExpCapDirCost := 0;
+            ExpSubDirCost := 0;
+            ExpCapOvhdCost := 0;
+            ExpMfgOvhdCost := 0;
+            MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+            MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+              ProdOrderLine, ShareOfTotalCapCost, ExpMatCost,
+              ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+            TotalExpMatCost += ExpMatCost;
+            TotalExpMfgOvhdCost += ExpMfgOvhdCost;
+        until ProdOrderLine.Next() = 0;
+
+        // [THEN] Total Material Cost = 2000 (100 unit cost * 1 qty per * 20 total qty)
+        Assert.AreEqual(UnitCost * 2 * QtyPerLine, TotalExpMatCost, 'Total Expected Material Cost is incorrect');
+
+        // [THEN] Total Manufacturing Overhead = 200 (10% of 2000), not 300
+        Assert.AreEqual(Round(TotalExpMatCost * IndirectCostPct / 100), TotalExpMfgOvhdCost, 'Total Expected Manufacturing Overhead is incorrect');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

