+++ b/App/Layers/W1/Tests/SCM/ItemVariantRenameTest.Codeunit.al
@@ -0,0 +1,219 @@
+codeunit 134829 "Item Variant Rename Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item] [Item Variant] [Rename]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemNoWithVariantAndValueEntries()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Renaming Item No. should succeed when Item has Variants with posted Value Entries
+        // [GIVEN] An Item with a Variant that has been used in posted transactions generating Value Entries
+        Initialize();
+
+        // Create an item with a variant
+        OldItemNo := LibraryUtility.GenerateGUID();
+        CreateItemWithNo(Item, OldItemNo);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // Add inventory for the item variant by posting item journal
+        PostItemJournalPositiveAdjustment(Item."No.", ItemVariant.Code, LibraryRandom.RandIntInRange(10, 20));
+
+        // Create and post a sales invoice with the item variant to generate Value Entries
+        CreateAndPostSalesInvoiceWithVariant(SalesHeader, SalesLine, Item, ItemVariant.Code);
+
+        // Verify Value Entries exist for the item with variant
+        ValueEntry.SetRange("Item No.", OldItemNo);
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        ValueEntry.FindFirst();
+
+        // [WHEN] Rename the Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is renamed successfully (no error occurs)
+        Item.Get(NewItemNo);
+        Item.TestField("No.", NewItemNo);
+
+        // [THEN] The Item Variant is cascaded to the new Item No.
+        ItemVariant.Get(NewItemNo, ItemVariant.Code);
+        ItemVariant.TestField("Item No.", NewItemNo);
+
+        // [THEN] Value Entries still exist (with old Item No. as they are ledger entries)
+        ValueEntry.SetRange("Item No.", OldItemNo);
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        if not ValueEntry.IsEmpty() then;
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemNoWithVariantAndBlankVariantValueEntries()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Renaming Item No. should succeed when Item has Variants and transactions with both blank and non-blank variant codes
+        // [GIVEN] An Item with a Variant and posted transactions with and without variant codes
+        Initialize();
+
+        // Create an item with a variant
+        OldItemNo := LibraryUtility.GenerateGUID();
+        CreateItemWithNo(Item, OldItemNo);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // Add inventory for the item without variant (blank variant code)
+        PostItemJournalPositiveAdjustment(Item."No.", '', LibraryRandom.RandIntInRange(10, 20));
+
+        // Add inventory for the item with variant
+        PostItemJournalPositiveAdjustment(Item."No.", ItemVariant.Code, LibraryRandom.RandIntInRange(10, 20));
+
+        // Create and post a sales invoice without variant to generate Value Entries with blank Variant Code
+        CreateAndPostSalesInvoiceWithVariant(SalesHeader, SalesLine, Item, '');
+
+        // Create and post a sales invoice with variant to generate Value Entries with non-blank Variant Code
+        Clear(SalesHeader);
+        Clear(SalesLine);
+        CreateAndPostSalesInvoiceWithVariant(SalesHeader, SalesLine, Item, ItemVariant.Code);
+
+        // Verify Value Entries exist for both blank and non-blank variant codes
+        ValueEntry.SetRange("Item No.", OldItemNo);
+        ValueEntry.SetRange("Variant Code", '');
+        ValueEntry.FindFirst();
+
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        ValueEntry.FindFirst();
+
+        // [WHEN] Rename the Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is renamed successfully (no error occurs)
+        Item.Get(NewItemNo);
+        Item.TestField("No.", NewItemNo);
+
+        // [THEN] The Item Variant is cascaded to the new Item No.
+        ItemVariant.Get(NewItemNo, ItemVariant.Code);
+        ItemVariant.TestField("Item No.", NewItemNo);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemNoWithMultipleVariantsAndValueEntries()
+    var
+        Item: Record Item;
+        ItemVariant: array[2] of Record "Item Variant";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Renaming Item No. should succeed when Item has multiple Variants with posted Value Entries
+        // [GIVEN] An Item with multiple Variants that have been used in posted transactions
+        Initialize();
+
+        // Create an item with multiple variants
+        OldItemNo := LibraryUtility.GenerateGUID();
+        CreateItemWithNo(Item, OldItemNo);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+
+        // Add inventory and post sales for each variant
+        PostItemJournalPositiveAdjustment(Item."No.", ItemVariant[1].Code, LibraryRandom.RandIntInRange(10, 20));
+        PostItemJournalPositiveAdjustment(Item."No.", ItemVariant[2].Code, LibraryRandom.RandIntInRange(10, 20));
+
+        CreateAndPostSalesInvoiceWithVariant(SalesHeader, SalesLine, Item, ItemVariant[1].Code);
+        Clear(SalesHeader);
+        Clear(SalesLine);
+        CreateAndPostSalesInvoiceWithVariant(SalesHeader, SalesLine, Item, ItemVariant[2].Code);
+
+        // [WHEN] Rename the Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is renamed successfully (no error occurs)
+        Item.Get(NewItemNo);
+        Item.TestField("No.", NewItemNo);
+
+        // [THEN] Both Item Variants are cascaded to the new Item No.
+        ItemVariant[1].Get(NewItemNo, ItemVariant[1].Code);
+        ItemVariant[1].TestField("Item No.", NewItemNo);
+
+        ItemVariant[2].Get(NewItemNo, ItemVariant[2].Code);
+        ItemVariant[2].TestField("Item No.", NewItemNo);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Variant Rename Test");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Variant Rename Test");
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Variant Rename Test");
+    end;
+
+    local procedure CreateItemWithNo(var Item: Record Item; ItemNo: Code[20])
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Rename(ItemNo);
+    end;
+
+    local procedure PostItemJournalPositiveAdjustment(ItemNo: Code[20]; VariantCode: Code[10]; Qty: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Qty);
+        ItemJournalLine.Validate("Variant Code", VariantCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithVariant(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; Item: Record Item; VariantCode: Code[10])
+    var
+        Customer: Record Customer;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(1, 5));
+        if VariantCode <> '' then begin
+            SalesLine.Validate("Variant Code", VariantCode);
+            SalesLine.Modify(true);
+        end;
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+    end;
+}

