+        ShopifyUnitCost: Decimal;
+    begin
+        // [SCENARIO] When importing a product from Shopify, if the shop has a Currency Code set,
+        // the Unit Price and Unit Cost should be converted from FCY to LCY using the exchange rate.
+
+        // [GIVEN] A shop with "SKU Mapping" = "Item No." and a Currency Code set with exchange rate
+        Shop := InitializeTest.CreateShop();
+        Shop."SKU Mapping" := "Shpfy SKU Mapping"::"Item No.";
+
+        // [GIVEN] A currency with exchange rate (e.g., 1 FCY = 0.5 LCY means dividing by 2)
+        Currency.Init();
+        Currency.Code := 'TST';
+        Currency.Description := 'Test Currency';
+        if not Currency.Insert() then
+            Currency.Modify();
+
+        ExchangeRateAmt := 2; // 1 FCY = 0.5 LCY (exchange rate factor of 2)
+        CurrencyExchangeRate.Init();
+        CurrencyExchangeRate."Currency Code" := Currency.Code;
+        CurrencyExchangeRate."Starting Date" := WorkDate();
+        CurrencyExchangeRate."Exchange Rate Amount" := 100;
+        CurrencyExchangeRate."Relational Exch. Rate Amount" := 100 * ExchangeRateAmt;
+        CurrencyExchangeRate."Adjustment Exch. Rate Amount" := 100;
+        CurrencyExchangeRate."Relational Adjmt Exch Rate Amt" := 100 * ExchangeRateAmt;
+        if not CurrencyExchangeRate.Insert() then
+            CurrencyExchangeRate.Modify();
+
+        Shop."Currency Code" := Currency.Code;
+        Shop.Modify();
+
+        // [GIVEN] A Shopify variant with specific Price and Unit Cost in FCY
+        ShopifyVariant := ProductInitTest.CreateStandardProduct(Shop);
+
+        ShopifyPrice := 5000;
+        ShopifyUnitCost := 2500;
+        ShopifyVariant.Price := ShopifyPrice;
+        ShopifyVariant."Unit Cost" := ShopifyUnitCost;
