+        ExpectedUnitCost := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(WorkDate(), Currency.Code, ShopifyUnitCost, CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
