diff --git a/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailWarningDueDate.Codeunit.al b/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailWarningDueDate.Codeunit.al
