index 00000000..7dbab77a
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailWarningDueDate.Codeunit.al
@@ -0,0 +1,180 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Assembly.Test;
+
+using Microsoft.Assembly.Document;
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.BOM;
+using Microsoft.Inventory.Journal;
+using Microsoft.Inventory.Location;
+using Microsoft.Manufacturing.Setup;
+using System.Environment.Configuration;
+
+codeunit 137999 "SCM Asm Avail Warning DueDate"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        NotificationLifecycleMgt: Codeunit "Notification Lifecycle Mgt.";
+        Initialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Asm Avail Warning DueDate");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Asm Avail Warning DueDate");
+
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Asm Avail Warning DueDate");
+    end;
+
+    [Test]
+    [HandlerFunctions('DueDateBeforeWorkDateMsgHandler')]
+    [Scope('OnPrem')]
+    procedure AvailWarningConsidersDueDateNotFutureDemand()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        AsmHeader1: Record "Assembly Header";
+        AsmHeader2: Record "Assembly Header";
+        AsmLine1: Record "Assembly Line";
+        AsmLine2: Record "Assembly Line";
+        Location: Record Location;
+        MfgSetup: Record "Manufacturing Setup";
+        OldDefSafetyLeadTime: DateFormula;
+        ZeroDateFormula: DateFormula;
+        Order1DueDate: Date;
+        Order2DueDate: Date;
+        QtyPerComponent: Decimal;
+    begin
+        // [SCENARIO] Availability warning on Assembly Order should consider Due Date, not all future demand
+        // [GIVEN] An assembled item with one component (Qty per = 2)
+        // [GIVEN] Assembly Order 1 for 1 qty due on 02/13/25, requiring 2 components
+        // [GIVEN] 2 pcs of component in inventory
+        // [GIVEN] Assembly Order 2 for 3 qty due on 02/18/25, requiring 6 components
+        // [WHEN] Checking availability warning on Assembly Order 1
+        // [THEN] Assembly Order 1 should show NO availability warning because 2 components are available for its due date
+
+        Initialize();
+
+        // Setup dates - Order 1 is 5 days before Order 2
+        Order1DueDate := WorkDate();
+        Order2DueDate := CalcDate('<+5D>', Order1DueDate);
+        QtyPerComponent := 2;
+
+        // Ensure Manufacturing Setup has zero default safety lead time to avoid date complications
+        MfgSetup.Get();
+        OldDefSafetyLeadTime := MfgSetup."Default Safety Lead Time";
+        Evaluate(ZeroDateFormula, '<0D>');
+        MfgSetup.Validate("Default Safety Lead Time", ZeroDateFormula);
+        MfgSetup.Modify(true);
+
+        // Create location
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // Create assembled item with one component (Qty per = 2)
+        LibraryInventory.CreateItem(ChildItem);
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::Assembly);
+        ParentItem.Validate("Safety Lead Time", ZeroDateFormula);
+        ParentItem.Modify(true);
+        LibraryInventory.CreateBOMComponent(
+            BOMComponent, ParentItem."No.", BOMComponent.Type::Item, ChildItem."No.",
+            QtyPerComponent, ChildItem."Base Unit of Measure");
+
+        // Create Assembly Order 1 for 1 qty (needs 2 components) due on Order1DueDate
+        Clear(AsmHeader1);
+        AsmHeader1."Document Type" := AsmHeader1."Document Type"::Order;
+        AsmHeader1.Insert(true);
+        AsmHeader1.Validate("Due Date", Order1DueDate);
+        AsmHeader1.Validate("Location Code", Location.Code);
+        AsmHeader1.Validate("Item No.", ParentItem."No.");
+        AsmHeader1.Validate(Quantity, 1);
+        AsmHeader1.Modify(true);
+        NotificationLifecycleMgt.RecallAllNotifications();
+
+        // Verify initial availability warning is shown (no inventory yet)
+        AsmLine1.SetRange("Document Type", AsmHeader1."Document Type");
+        AsmLine1.SetRange("Document No.", AsmHeader1."No.");
+        AsmLine1.SetRange(Type, AsmLine1.Type::Item);
+        AsmLine1.FindFirst();
+        Assert.IsTrue(AsmLine1."Avail. Warning", 'Avail. Warning should be Yes initially when no inventory');
+
+        // Add 2 pcs of component to inventory (enough for Order 1)
+        AddItemToInventory(ChildItem, Location.Code, 2);
+
+        // Refresh and verify no availability warning on Order 1 (we have enough)
+        AsmLine1.Get(AsmLine1."Document Type", AsmLine1."Document No.", AsmLine1."Line No.");
+        Assert.IsFalse(AsmLine1."Avail. Warning", 'Avail. Warning should be No after adding inventory');
+
+        // Create Assembly Order 2 for 3 qty (needs 6 components) due on Order2DueDate (later)
+        Clear(AsmHeader2);
+        AsmHeader2."Document Type" := AsmHeader2."Document Type"::Order;
+        AsmHeader2.Insert(true);
+        AsmHeader2.Validate("Due Date", Order2DueDate);
+        AsmHeader2.Validate("Location Code", Location.Code);
+        AsmHeader2.Validate("Item No.", ParentItem."No.");
+        AsmHeader2.Validate(Quantity, 3);
+        AsmHeader2.Modify(true);
+        NotificationLifecycleMgt.RecallAllNotifications();
+
+        // Verify Order 2 has availability warning (needs 6, only 2 available)
+        AsmLine2.SetRange("Document Type", AsmHeader2."Document Type");
+        AsmLine2.SetRange("Document No.", AsmHeader2."No.");
+        AsmLine2.SetRange(Type, AsmLine2.Type::Item);
+        AsmLine2.FindFirst();
+        Assert.IsTrue(AsmLine2."Avail. Warning", 'Order 2 should have Avail. Warning (needs 6, only 2 available)');
+
+        // [CRITICAL TEST] Recheck Order 1 - should still have NO availability warning
+        // because it only needs 2 components and we have 2 in inventory
+        // The bug was that it was considering ALL demand (including Order 2's 6 components)
+        AsmLine1.Get(AsmLine1."Document Type", AsmLine1."Document No.", AsmLine1."Line No.");
+        Assert.IsFalse(AsmLine1."Avail. Warning",
+            'Order 1 should NOT have Avail. Warning - it has enough inventory for its due date, regardless of future demand');
+
+        // Cleanup
+        MfgSetup.Validate("Default Safety Lead Time", OldDefSafetyLeadTime);
+        MfgSetup.Modify(true);
