diff --git a/App/Layers/W1/Tests/Job/JobGLJournalAmountLCY.Codeunit.al b/App/Layers/W1/Tests/Job/JobGLJournalAmountLCY.Codeunit.al
new file mode 100644
index 00000000..fcb9355e
--- /dev/null
+++ b/App/Layers/W1/Tests/Job/JobGLJournalAmountLCY.Codeunit.al
@@ -0,0 +1,140 @@
+codeunit 136399 "Job G/L Journal Amount LCY"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Job] [G/L Journal]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        Initialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AmountLCYChangeUpdatesJobCostFieldsWithCurrency()
+    var
+        JobTask: Record "Job Task";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        CurrencyCode: Code[10];
+        NewAmountLCY: Decimal;
+        ExpectedJobUnitCost: Decimal;
+        ExpectedJobTotalCost: Decimal;
+    begin
+        // [SCENARIO] When Amount (LCY) is changed on a Gen. Journal Line with currency code and Job Task set, 
+        // Job Unit Cost, Job Unit Cost (LCY), Job Total Cost, and Job Total Cost (LCY) should be updated.
+
+        // [GIVEN] A Gen. Journal Line with Currency Code, Job No., Job Task No., and Job Quantity set.
+        Initialize();
+        CreateJobWithJobTask(JobTask);
+        CurrencyCode := CreateCurrency();
+        CreateJobJournalBatch(GenJournalBatch);
+        CreateJobGLJournalLineWithCurrency(GenJournalLine, GenJournalBatch, JobTask, CurrencyCode);
+
+        // [WHEN] Changing the Amount (LCY) field on the Gen. Journal Line.
+        NewAmountLCY := LibraryRandom.RandDecInRange(200, 500, 2);
+        GenJournalLine.Validate("Amount (LCY)", NewAmountLCY);
+        GenJournalLine.Modify(true);
+
+        // [THEN] The Job Cost fields should be updated based on the new Amount (LCY).
+        GenJournalLine.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name", GenJournalLine."Line No.");
+        ExpectedJobUnitCost := (GenJournalLine.Amount - GenJournalLine."VAT Amount") / GenJournalLine."Job Quantity";
+        ExpectedJobTotalCost := (GenJournalLine.Amount - GenJournalLine."VAT Amount");
+
+        Assert.AreNotEqual(0, GenJournalLine."Job Unit Cost", 'Job Unit Cost should not be zero after Amount (LCY) change.');
+        Assert.AreNotEqual(0, GenJournalLine."Job Unit Cost (LCY)", 'Job Unit Cost (LCY) should not be zero after Amount (LCY) change.');
+        Assert.AreNotEqual(0, GenJournalLine."Job Total Cost", 'Job Total Cost should not be zero after Amount (LCY) change.');
+        Assert.AreNotEqual(0, GenJournalLine."Job Total Cost (LCY)", 'Job Total Cost (LCY) should not be zero after Amount (LCY) change.');
+
+        // Verify Job Total Cost (LCY) equals Amount (LCY) minus VAT Amount for Job Quantity = 1
+        // For general case, verify relationship between fields
+        Assert.AreEqual(
+            GenJournalLine."Job Unit Cost" * GenJournalLine."Job Quantity",
+            GenJournalLine."Job Total Cost",
+            'Job Total Cost should equal Job Unit Cost * Job Quantity.');
+        Assert.AreEqual(
+            GenJournalLine."Job Unit Cost (LCY)" * GenJournalLine."Job Quantity",
+            GenJournalLine."Job Total Cost (LCY)",
+            'Job Total Cost (LCY) should equal Job Unit Cost (LCY) * Job Quantity.');
+
+        // Tear Down: Delete newly created batch.
+        GenJournalBatch.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name");
+        GenJournalBatch.Delete(true);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Job G/L Journal Amount LCY");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Job G/L Journal Amount LCY");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Job G/L Journal Amount LCY");
+    end;
+
+    local procedure CreateJobWithJobTask(var JobTask: Record "Job Task")
+    var
+        Job: Record Job;
+    begin
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+    end;
+
+    local procedure CreateCurrency(): Code[10]
+    var
+        Currency: Record Currency;
+    begin
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.CreateRandomExchangeRate(Currency.Code);
+        exit(Currency.Code);
+    end;
+
+    local procedure CreateJobJournalBatch(var GenJournalBatch: Record "Gen. Journal Batch")
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+    begin
+        GenJournalTemplate.SetRange(Type, GenJournalTemplate.Type::Jobs);
+        LibraryERM.FindGenJournalTemplate(GenJournalTemplate);
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, GenJournalTemplate.Name);
+    end;
+
+    local procedure CreateJobGLJournalLineWithCurrency(var GenJournalLine: Record "Gen. Journal Line"; GenJournalBatch: Record "Gen. Journal Batch"; JobTask: Record "Job Task"; CurrencyCode: Code[10])
+    var
+        GLAccountNo: Code[20];
+        BalGLAccountNo: Code[20];
+    begin
+        GLAccountNo := LibraryERM.CreateGLAccountNo();
+        BalGLAccountNo := LibraryERM.CreateGLAccountNo();
+
+        // Create the line with Amount set
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice,
+            GenJournalLine."Account Type"::"G/L Account", GLAccountNo, LibraryRandom.RandDecInRange(100, 200, 2));
+
+        GenJournalLine.Validate("Bal. Account Type", GenJournalLine."Bal. Account Type"::"G/L Account");
+        GenJournalLine.Validate("Bal. Account No.", BalGLAccountNo);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate("Job Line Type", GenJournalLine."Job Line Type"::"Both Budget and Billable");
+        GenJournalLine.Validate("Job No.", JobTask."Job No.");
+        GenJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        GenJournalLine.Validate("Job Quantity", LibraryRandom.RandIntInRange(1, 10));
+        GenJournalLine.Modify(true);
+    end;
+}

