+codeunit 134124 "Price List Line Variant Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Price Calculation] [Price List Line] [Variant]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPriceCalculation: Codeunit "Library - Price Calculation";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure VariantCodeNotPresetOnNewPriceListLineForSameItem()
+    var
+        PriceListHeader: Record "Price List Header";
+        Item: Record Item;
+        ItemVariant: array[3] of Record "Item Variant";
+        SalesPriceList: TestPage "Sales Price List";
+    begin
+        // [SCENARIO] When creating a new price list line for an item with variants, 
+        // the variant code should NOT be automatically preset from the previously created line.
+        // Bug: The variant "Blue" was automatically preset for the next line.
+        // Expected: The Variant should not be preset for the next line.
+
+        // [GIVEN] Initialize
+        Initialize(true);
+
+        // [GIVEN] Create an item with 3 variants (e.g., "Blue", "Red", "Green")
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[3], Item."No.");
+
+        // [GIVEN] Create a Sales Price List Header
+        LibraryPriceCalculation.CreatePriceHeader(
+            PriceListHeader, PriceListHeader."Price Type"::Sale,
+            PriceListHeader."Source Type"::"All Customers", '');
+
+        // [GIVEN] Open the Sales Price List page
+        SalesPriceList.OpenEdit();
+        SalesPriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [GIVEN] Create a price list line with item and first variant (e.g., "Blue")
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item."No.");
+        SalesPriceList.Lines."Variant Code".SetValue(ItemVariant[1].Code);
+
+        // [WHEN] Create a second price list line for the same item
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item."No.");
+
+        // [THEN] The Variant Code should be empty (NOT preset with "Blue" from previous line)
+        Assert.AreEqual('', SalesPriceList.Lines."Variant Code".Value(),
+            'Variant Code should NOT be preset from the previous line when creating a new price list line.');
+    end;
+
+    [Test]
+    procedure VariantCodeNotPresetOnNewPriceListLineForDifferentItem()
+    var
+        PriceListHeader: Record "Price List Header";
+        Item1, Item2 : Record Item;
+        ItemVariant: Record "Item Variant";
+        SalesPriceList: TestPage "Sales Price List";
+    begin
+        // [SCENARIO] When creating a new price list line for a different item,
+        // the variant code should NOT be preset from the previously created line.
+
+        // [GIVEN] Initialize
+        Initialize(true);
+
+        // [GIVEN] Create first item with a variant
+        LibraryInventory.CreateItem(Item1);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item1."No.");
+
+        // [GIVEN] Create second item without variants
+        LibraryInventory.CreateItem(Item2);
+
+        // [GIVEN] Create a Sales Price List Header
+        LibraryPriceCalculation.CreatePriceHeader(
+            PriceListHeader, PriceListHeader."Price Type"::Sale,
+            PriceListHeader."Source Type"::"All Customers", '');
+
+        // [GIVEN] Open the Sales Price List page
+        SalesPriceList.OpenEdit();
+        SalesPriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [GIVEN] Create a price list line with first item and variant
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item1."No.");
+        SalesPriceList.Lines."Variant Code".SetValue(ItemVariant.Code);
+
+        // [WHEN] Create a second price list line for a different item
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item2."No.");
+
+        // [THEN] The Variant Code should be empty
+        Assert.AreEqual('', SalesPriceList.Lines."Variant Code".Value(),
+            'Variant Code should NOT be preset when creating a new price list line for a different item.');
+    end;
+
+    [Test]
+    procedure VariantCodeNotPresetOnNewPurchasePriceListLine()
+    var
+        PriceListHeader: Record "Price List Header";
+        Item: Record Item;
+        ItemVariant: array[2] of Record "Item Variant";
+        PurchasePriceList: TestPage "Purchase Price List";
+    begin
+        // [SCENARIO] When creating a new purchase price list line for an item with variants,
+        // the variant code should NOT be automatically preset from the previously created line.
+
+        // [GIVEN] Initialize
+        Initialize(true);
+
+        // [GIVEN] Create an item with 2 variants
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+
+        // [GIVEN] Create a Purchase Price List Header
+        LibraryPriceCalculation.CreatePriceHeader(
+            PriceListHeader, PriceListHeader."Price Type"::Purchase,
+            PriceListHeader."Source Type"::"All Vendors", '');
+
+        // [GIVEN] Open the Purchase Price List page
+        PurchasePriceList.OpenEdit();
+        PurchasePriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [GIVEN] Create a price list line with item and first variant
+        PurchasePriceList.Lines.New();
+        PurchasePriceList.Lines."Product No.".SetValue(Item."No.");
+        PurchasePriceList.Lines."Variant Code".SetValue(ItemVariant[1].Code);
+
+        // [WHEN] Create a second price list line for the same item
+        PurchasePriceList.Lines.New();
+        PurchasePriceList.Lines."Product No.".SetValue(Item."No.");
+
+        // [THEN] The Variant Code should be empty (NOT preset from previous line)
+        Assert.AreEqual('', PurchasePriceList.Lines."Variant Code".Value(),
+            'Variant Code should NOT be preset from the previous line when creating a new purchase price list line.');
+    end;
+
+    local procedure Initialize(Enable: Boolean)
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Price List Line Variant Test");
+        LibraryVariableStorage.Clear();
+        LibraryPriceCalculation.EnableExtendedPriceCalculation(Enable);
+        LibraryPriceCalculation.SetUseCustomLookup(true);
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Price List Line Variant Test");
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Price List Line Variant Test");
+    end;
+}

