+++ b/App/Layers/W1/Tests/Workflow/WFPurchQuoteNotifySender.Codeunit.al
@@ -0,0 +1,189 @@
+codeunit 134199 "WF Purch Quote Notify Sender"
+{
+    // [FEATURE] [Workflow] [Purchase Quote] [Notification] [Notify Sender]
+    // Tests for the fix of the bug where requesting approval of a Purchase Quote with 
+    // "Notify Sender" activated triggers an error message about Pay-to Name 2 field type change.
+    // The issue was that when CreateNotificationEntry was called with a Purchase Header
+    // (not an Approval Entry), the code tried to read the Sender ID field from the wrong table.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryWorkflow: Codeunit "Library - Workflow";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CreateNotificationEntryForPurchaseHeaderWithNotifySender()
+    var
+        Workflow: Record Workflow;
+        WorkflowStep: Record "Workflow Step";
+        SubWorkflowStep: Record "Workflow Step";
+        WorkflowStepArgument: Record "Workflow Step Argument";
+        WorkflowStepInstance: Record "Workflow Step Instance";
+        PurchaseHeader: Record "Purchase Header";
+        NotificationEntry: Record "Notification Entry";
+        WorkflowEventHandling: Codeunit "Workflow Event Handling";
+        WorkflowResponseHandling: Codeunit "Workflow Response Handling";
+        RecVar: Variant;
+        WorkflowInstanceId: Guid;
+        EntryPointStepID: Integer;
+        NotificationStepId: Integer;
+    begin
+        // [SCENARIO] System creates Notification Entry when workflow processes "Create notification for <Sender>" 
+        // response for a Purchase Quote with "Notify Sender" enabled.
+        // This scenario reproduces the bug where the code incorrectly tried to read "Sender ID" from 
+        // Purchase Header (field 6 = "Pay-to Name 2") instead of handling it as a document record.
+        Initialize();
+
+        // [GIVEN] Workflow with "Create notification for <Sender>" response step for Purchase Quote
+        LibraryWorkflow.CreateWorkflow(Workflow);
+
+        EntryPointStepID :=
+            LibraryWorkflow.InsertEntryPointEventStep(Workflow, WorkflowEventHandling.RunWorkflowOnSendPurchaseDocForApprovalCode());
+
+        NotificationStepId :=
+            LibraryWorkflow.InsertResponseStep(Workflow, WorkflowResponseHandling.CreateNotificationEntryCode(), EntryPointStepID);
+
+        LibraryWorkflow.InsertNotificationArgument(NotificationStepId, UserId, 0, '');
+
+        // [GIVEN] The workflow step argument has "Notify Sender" enabled
+        WorkflowStep.Get(Workflow.Code, NotificationStepId);
+        WorkflowStepArgument.Get(WorkflowStep.Argument);
+        WorkflowStepArgument.Validate("Notify Sender", true);
+        WorkflowStepArgument.Validate("Notification Entry Type", WorkflowStepArgument."Notification Entry Type"::Approval);
+        WorkflowStepArgument.Modify(true);
+
+        WorkflowInstanceId := CreateGuid();
+        WorkflowStep.CreateInstance(WorkflowInstanceId, Workflow.Code, 0, SubWorkflowStep);
+        WorkflowStepInstance.SetRange(ID, WorkflowInstanceId);
+        WorkflowStepInstance.FindFirst();
+
+        // [GIVEN] A Purchase Quote exists
+        CreatePurchaseQuote(PurchaseHeader);
+
+        RecVar := PurchaseHeader;
+
+        // [WHEN] System processes "Create notification for <Sender>" response step instance 
+        // with the Purchase Header directly (not wrapped in ApprovalEntry)
+        // Before the fix, this would cause error:
+        // "The definition of the Pay-to Name 2 field has changed; old type: Code, new type: Text"
+        WorkflowResponseHandling.ExecuteResponse(RecVar, WorkflowStepInstance, PurchaseHeader);
