+            'The notification should be sent to the current user (sender)');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CreateNotificationEntryForPurchaseHeaderWithSpecificUser()
+    var
+        Workflow: Record Workflow;
+        WorkflowStep: Record "Workflow Step";
+        SubWorkflowStep: Record "Workflow Step";
+        WorkflowStepArgument: Record "Workflow Step Argument";
+        WorkflowStepInstance: Record "Workflow Step Instance";
+        PurchaseHeader: Record "Purchase Header";
+        NotificationEntry: Record "Notification Entry";
+        WorkflowEventHandling: Codeunit "Workflow Event Handling";
+        WorkflowResponseHandling: Codeunit "Workflow Response Handling";
+        RecVar: Variant;
+        WorkflowInstanceId: Guid;
+        EntryPointStepID: Integer;
+        NotificationStepId: Integer;
+        NotificationUserID: Code[50];
+    begin
+        // [SCENARIO] System creates Notification Entry when workflow processes "Create notification" 
+        // response for a Purchase Quote with a specific user (not Notify Sender).
+        Initialize();
+
+        // [GIVEN] Workflow with "Create notification" response step for Purchase Quote with specific user
+        LibraryWorkflow.CreateWorkflow(Workflow);
+
+        EntryPointStepID :=
+            LibraryWorkflow.InsertEntryPointEventStep(Workflow, WorkflowEventHandling.RunWorkflowOnSendPurchaseDocForApprovalCode());
+
+        NotificationStepId :=
+            LibraryWorkflow.InsertResponseStep(Workflow, WorkflowResponseHandling.CreateNotificationEntryCode(), EntryPointStepID);
+
+        NotificationUserID := CopyStr(UserId, 1, 50);
+        LibraryWorkflow.InsertNotificationArgument(NotificationStepId, NotificationUserID, 0, '');
+
+        // [GIVEN] The workflow step argument has "Notify Sender" disabled (using specific user)
+        WorkflowStep.Get(Workflow.Code, NotificationStepId);
+        WorkflowStepArgument.Get(WorkflowStep.Argument);
+        WorkflowStepArgument.Validate("Notify Sender", false);
+        WorkflowStepArgument.Validate("Notification User ID", NotificationUserID);
+        WorkflowStepArgument.Validate("Notification Entry Type", WorkflowStepArgument."Notification Entry Type"::Approval);
+        WorkflowStepArgument.Modify(true);
+
+        WorkflowInstanceId := CreateGuid();
+        WorkflowStep.CreateInstance(WorkflowInstanceId, Workflow.Code, 0, SubWorkflowStep);
+        WorkflowStepInstance.SetRange(ID, WorkflowInstanceId);
+        WorkflowStepInstance.FindFirst();
+
+        // [GIVEN] A Purchase Quote exists
+        CreatePurchaseQuote(PurchaseHeader);
+
+        RecVar := PurchaseHeader;
+
+        // [WHEN] System processes "Create notification" response step instance 
+        // with the Purchase Header directly
+        WorkflowResponseHandling.ExecuteResponse(RecVar, WorkflowStepInstance, PurchaseHeader);
+
+        // [THEN] Notification Entry is created for the specified user without any error
+        NotificationEntry.SetRange("Triggered By Record", PurchaseHeader.RecordId);
+        Assert.RecordCount(NotificationEntry, 1);
+
+        // [THEN] The recipient should be the specified notification user
+        NotificationEntry.FindFirst();
+        Assert.AreEqual(NotificationUserID, NotificationEntry."Recipient User ID",
+            'The notification should be sent to the specified notification user');
+    end;
+
+    local procedure Initialize()
+    var
+        NotificationEntry: Record "Notification Entry";
+        ApprovalEntry: Record "Approval Entry";
+        UserSetup: Record "User Setup";
+    begin
+        LibraryWorkflow.SetUpEmailAccount();
