+    [Test]
+    [Scope('OnPrem')]
+    procedure RolledUpCapCostConsistentWithEmptyBOMAndNoBOM()
+    var
+        ParentItem: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        EmptyProductionBOMHeader: Record "Production BOM Header";
+        BOMBufferWithEmptyBOM: Record "BOM Buffer";
+        BOMBufferWithNoBOM: Record "BOM Buffer";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        CalculateBOMTree: Codeunit "Calculate BOM Tree";
+        TreeType: Option " ",Availability,Cost;
+        ItemFilter: Record Item;
+        QtyPerParent: Decimal;
+        RolledUpCapacityCostWithEmptyBOM: Decimal;
+        RolledUpCapacityCostWithNoBOM: Decimal;
+    begin
+        // [FEATURE] [BOM Tree] [Cost Shares]
+        // [SCENARIO] Rolled-up Capacity Cost should be consistent when a component has an empty Production BOM vs no Production BOM at all.
+        // Both scenarios should produce the same result because an empty BOM is functionally equivalent to no BOM.
+        Initialize();
+
+        // [GIVEN] A component item that is a manufacturing item (Replenishment System = Prod. Order)
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::"Prod. Order");
+        ComponentItem.Validate("Costing Method", ComponentItem."Costing Method"::Standard);
+        ComponentItem.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        ComponentItem.Modify(true);
+
+        // [GIVEN] An empty certified Production BOM (no lines)
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        EmptyProductionBOMHeader.Validate(Status, EmptyProductionBOMHeader.Status::Certified);
+        EmptyProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A parent item with a Production BOM that includes the component with quantity > 1
+        QtyPerParent := LibraryRandom.RandIntInRange(2, 10);
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Costing Method", ParentItem."Costing Method"::Standard);
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPerParent);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Assign the empty BOM to the component
+        ComponentItem.Validate("Production BOM No.", EmptyProductionBOMHeader."No.");
+        ComponentItem.Modify(true);
+
+        // [WHEN] Generate the BOM tree for the parent item with the component having an empty BOM
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferWithEmptyBOM, TreeType::Cost);
+
+        // [THEN] Find the component in the BOM buffer and capture its Rolled-up Capacity Cost
+        BOMBufferWithEmptyBOM.SetRange(Type, BOMBufferWithEmptyBOM.Type::Item);
+        BOMBufferWithEmptyBOM.SetRange("No.", ComponentItem."No.");
+        BOMBufferWithEmptyBOM.FindFirst();
+        RolledUpCapacityCostWithEmptyBOM := BOMBufferWithEmptyBOM."Rolled-up Capacity Cost";
+
+        // [GIVEN] Remove the Production BOM from the component (so it has no BOM at all)
+        ComponentItem.Validate("Production BOM No.", '');
+        ComponentItem.Modify(true);
+
+        // [WHEN] Generate the BOM tree again for the parent item with the component having no BOM
+        Clear(CalculateBOMTree);
+        BOMBufferWithNoBOM.Reset();
+        BOMBufferWithNoBOM.DeleteAll();
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferWithNoBOM, TreeType::Cost);
+
+        // [THEN] Find the component in the BOM buffer and capture its Rolled-up Capacity Cost
+        BOMBufferWithNoBOM.SetRange(Type, BOMBufferWithNoBOM.Type::Item);
+        BOMBufferWithNoBOM.SetRange("No.", ComponentItem."No.");
+        BOMBufferWithNoBOM.FindFirst();
+        RolledUpCapacityCostWithNoBOM := BOMBufferWithNoBOM."Rolled-up Capacity Cost";
+
+        // [VERIFY] The Rolled-up Capacity Cost should be the same in both scenarios
+        Assert.AreEqual(RolledUpCapacityCostWithEmptyBOM, RolledUpCapacityCostWithNoBOM,
+            'Rolled-up Capacity Cost should be consistent whether component has an empty BOM or no BOM at all');
+    end;
+
