+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        ItemTrackingCode: Record "Item Tracking Code";
+        ItemJournalLine: Record "Item Journal Line";
+        SalesHeaderOrder: Record "Sales Header";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesLineOrder: Record "Sales Line";
+        SalesLineInvoice: Record "Sales Line";
+        ReservationEntry: Record "Reservation Entry";
+        OriginalQuantity: Decimal;
+        ReducedQuantity: Decimal;
+    begin
+        // [FEATURE] [Item Tracking] [Sales Invoice] [Get Shipment Lines]
+        // [SCENARIO] When reducing quantity on a Sales Invoice line created from Get Shipment Lines, item tracking lines should be preserved.
+        // The issue occurs when the item has Reserve = Always, FIFO costing method, and item tracking.
+        // Without the fix, item tracking lines would be incorrectly deleted when quantity is reduced.
+        Initialize();
+
+        OriginalQuantity := LibraryRandom.RandIntInRange(5, 10);
+        ReducedQuantity := OriginalQuantity - 1;
+
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Item with Lot Tracking Code, Reserve = Always, and FIFO costing method.
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Modify(true);
+
+        // [GIVEN] Post positive inventory adjustment with Lot Item Tracking.
+        CreateAndPostItemJournalLineWithTracking(
+          ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LocationBlue.Code, OriginalQuantity + 10, AssignTracking::LotNo);
+
+        // [GIVEN] Shipped Sales Order with Lot Item Tracking.
+        AssignTracking := AssignTracking::None;
+        CreateAndPostSalesOrderWithTracking(
+          SalesHeaderOrder, SalesLineOrder, Customer."No.", Item."No.", LocationBlue.Code, OriginalQuantity);
+
+        // [GIVEN] Sales Invoice with lines copied from Sales Shipment by GetShipmentLines function.
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesLineInvoice."Document Type" := SalesHeaderInvoice."Document Type";
+        SalesLineInvoice."Document No." := SalesHeaderInvoice."No.";
+        LibrarySales.GetShipmentLines(SalesLineInvoice);
+
+        // Get the created sales invoice line
+        SalesLineInvoice.SetRange("Document Type", SalesHeaderInvoice."Document Type");
+        SalesLineInvoice.SetRange("Document No.", SalesHeaderInvoice."No.");
+        SalesLineInvoice.SetRange(Type, SalesLineInvoice.Type::Item);
+        SalesLineInvoice.SetRange("No.", Item."No.");
+        SalesLineInvoice.FindFirst();
+
+        // Verify item tracking lines exist before quantity reduction
+        FilterReservationEntry(ReservationEntry, SalesLineInvoice);
+        Assert.IsFalse(ReservationEntry.IsEmpty(), 'Item tracking lines should exist before quantity reduction');
+
+        // [WHEN] Reduce the quantity on the Sales Invoice line.
+        SalesLineInvoice.Validate(Quantity, ReducedQuantity);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking lines should still exist (not be deleted).
+        FilterReservationEntry(ReservationEntry, SalesLineInvoice);
+        Assert.IsFalse(ReservationEntry.IsEmpty(), 'Item tracking lines should be preserved after reducing quantity on invoice line created from shipment');
+
+        // Clean up
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Sales Line-Reserve Tests");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Sales Line-Reserve Tests");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        NoSeriesSetup();
+        CreateLocationSetup();
+        ItemJournalSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Sales Line-Reserve Tests");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Shipment Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Invoice Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateLocationSetup()
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationBlue);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        Clear(ItemJournalTemplate);
+        ItemJournalTemplate.Init();
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+
+        Clear(ItemJournalBatch);
+        ItemJournalBatch.Init();
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+    end;
+
+    local procedure CreateAndPostItemJournalLineWithTracking(EntryType: Enum "Item Ledger Document Type"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; AssignTrackingOption: Option)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+          ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name, EntryType, ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+
+        AssignTracking := AssignTrackingOption;
+        ItemJournalLine.OpenItemTrackingLines(false);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndPostSalesOrderWithTracking(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; CustomerNo: Code[20]; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal)
+    begin
+        CreateSalesDocument(SalesHeader, SalesLine, SalesHeader."Document Type"::Order, ItemNo, LocationCode, Quantity, CustomerNo);
+        SalesLine.OpenItemTrackingLines();
+        LibrarySales.PostSalesDocument(SalesHeader, true, false);
+    end;
+
+    local procedure CreateSalesDocument(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; DocumentType: Enum "Sales Document Type"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; CustomerNo: Code[20])
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, DocumentType, CustomerNo);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, Quantity);
+        SalesLine.Validate("Location Code", LocationCode);
+        SalesLine.Modify(true);
+    end;
+
+    local procedure FilterReservationEntry(var ReservationEntry: Record "Reservation Entry"; SalesLine: Record "Sales Line")
+    begin
+        ReservationEntry.SetRange("Source Type", Database::"Sales Line");
+        ReservationEntry.SetRange("Source Subtype", SalesLine."Document Type");
+        ReservationEntry.SetRange("Source ID", SalesLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLine."Line No.");
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    begin
+        case AssignTracking of
+            AssignTracking::LotNo:
+                ItemTrackingLines."Assign Lot No.".Invoke();
+            AssignTracking::SerialNo:
+                ItemTrackingLines."Assign Serial No.".Invoke();
+            AssignTracking::None:
+                ItemTrackingLines."Select Entries".Invoke();
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingSummaryPageHandler(var ItemTrackingSummary: TestPage "Item Tracking Summary")
+    begin
+        ItemTrackingSummary.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure GetShipmentLinesPageHandler(var GetShipmentLines: TestPage "Get Shipment Lines")
+    begin
+        GetShipmentLines.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMWhseShptPostPreview.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMWhseShptPostPreview.Codeunit.al
new file mode 100644
index 00000000..5fa0f14f
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMWhseShptPostPreview.Codeunit.al
@@ -0,0 +1,129 @@
+codeunit 137999 "SCM Whse. Shpt. Post Preview"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Shipment] [Posting Preview]
+        isInitialized := false;
+    end;
+
+    var
+        LocationWithShipment: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('GLPostingPreviewPageHandler')]
+    [Scope('OnPrem')]
+    procedure WarehouseShipmentExistsAfterPreviewPostingTransferOrder()
+    var
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        WarehouseShipment: TestPage "Warehouse Shipment";
+        WhseShipmentNo: Code[20];
+        Quantity: Decimal;
+    begin
+        // [SCENARIO 546789] Warehouse shipment line linked to a Transfer Order should not disappear after Preview posting
+        // [GIVEN] A location with "Require Shipment" enabled
+        // [GIVEN] A Transfer Order with a warehouse shipment
+        // [WHEN] Preview Post is invoked from the Warehouse Shipment page
+        // [THEN] The warehouse shipment and its lines should still exist
+        Initialize();
+
+        // [GIVEN] Create an Item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create and post a positive adjustment journal line for the item and location
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(
+            ItemJournalLine, Item."No.", LocationWithShipment.Code, '', Quantity);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Create Transfer Order from location with shipment to another location
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, LocationWithShipment.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryWarehouse.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Quantity);
+        TransferLine.Validate("Qty. to Ship", Quantity);
+        TransferLine.Modify(true);
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Create Warehouse Shipment from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        WhseShipmentNo := LibraryWarehouse.FindWhseShipmentNoBySourceDoc(
+            DATABASE::"Transfer Line", 0, TransferHeader."No.");
+        WarehouseShipmentHeader.Get(WhseShipmentNo);
+        Commit();
+
+        // [WHEN] Preview Posting action is invoked on the Warehouse Shipment page
+        WarehouseShipment.OpenEdit();
+        WarehouseShipment.GoToRecord(WarehouseShipmentHeader);
+        WarehouseShipment.PreviewPosting.Invoke();
+
+        // [THEN] The warehouse shipment header still exists
+        Assert.IsTrue(
+            WarehouseShipmentHeader.Get(WhseShipmentNo),
+            'Warehouse Shipment Header should still exist after preview posting.');
+
+        // [THEN] The warehouse shipment line for the transfer order still exists
+        WarehouseShipmentLine.SetRange("No.", WhseShipmentNo);
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Outbound Transfer");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.IsFalse(
+            WarehouseShipmentLine.IsEmpty(),
+            'Warehouse Shipment Line should still exist after preview posting.');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse. Shpt. Post Preview");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse. Shpt. Post Preview");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        // Create location with Require Shipment
+        CreateLocationWithRequireShipment(LocationWithShipment);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+
+        // Create Warehouse Employee
+        WarehouseEmployee.DeleteAll(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationWithShipment.Code, true);
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse. Shpt. Post Preview");
+    end;
+
+    local procedure CreateLocationWithRequireShipment(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, false, false, false, false, true);
+    end;
+
+    [PageHandler]
+    [Scope('OnPrem')]
+    procedure GLPostingPreviewPageHandler(var GLPostingPreview: TestPage "G/L Posting Preview")
+    begin
+        // Close the preview page - the test is verifying that the shipment still exists after preview
+        GLPostingPreview.Close();
+    end;
+}

diff --git a/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al b/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al
new file mode 100644
index 00000000..847efd79
--- /dev/null
+++ b/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al
@@ -0,0 +1,190 @@
+codeunit 136218 "Contact Next Task Date"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Contact] [Task] [FlowField]
+    end;
+
+    var
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateIncludesOrganizerTasks()
+    var
+        Contact: Record Contact;
+        Todo: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [FEATURE] [Contact] [Task]
+        // [SCENARIO] Next Task Date on Contact should include tasks with System To-do Type = Organizer
+        // Bug fix: Next Task Date had a fixed filter for "System To-do Type" = "Contact Attendee" only,
+        // which excluded tasks where the contact is the organizer.
+        Initialize();
+
+        // [GIVEN] A Contact of type Company
+        LibraryMarketing.CreateCompanyContact(Contact);
+
+        // [GIVEN] A Salesperson with email for the task
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] A Task with System To-do Type = Organizer linked to the Contact
+        TaskDate := WorkDate() + 5;
+        CreateOrganizerTaskForContact(Todo, Contact, SalespersonPurchaser.Code, TaskDate);
+
+        // [WHEN] Calculate the Next Task Date FlowField on the Contact
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] The Next Task Date should equal the task's date
+        Assert.AreEqual(TaskDate, Contact."Next Task Date", 'Next Task Date should include Organizer tasks');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateIncludesContactAttendeeTasks()
+    var
+        Contact: Record Contact;
+        Todo: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [FEATURE] [Contact] [Task]
+        // [SCENARIO] Next Task Date on Contact should include tasks with System To-do Type = Contact Attendee
+        Initialize();
+
+        // [GIVEN] A Contact of type Company
+        LibraryMarketing.CreateCompanyContact(Contact);
+
+        // [GIVEN] A Salesperson for the task
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] A Task with System To-do Type = Contact Attendee linked to the Contact
+        TaskDate := WorkDate() + 3;
+        CreateContactAttendeeTaskForContact(Todo, Contact, SalespersonPurchaser.Code, TaskDate);
+
+        // [WHEN] Calculate the Next Task Date FlowField on the Contact
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] The Next Task Date should equal the task's date
+        Assert.AreEqual(TaskDate, Contact."Next Task Date", 'Next Task Date should include Contact Attendee tasks');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateReturnsMinimumDate()
+    var
+        Contact: Record Contact;
+        OrganizerTodo: Record "To-do";
+        AttendeeTodo: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        OrganizerTaskDate: Date;
+        AttendeeTaskDate: Date;
+    begin
+        // [FEATURE] [Contact] [Task]
+        // [SCENARIO] Next Task Date on Contact should return the minimum date from both Organizer and Contact Attendee tasks
+        Initialize();
+
+        // [GIVEN] A Contact of type Company
+        LibraryMarketing.CreateCompanyContact(Contact);
+
+        // [GIVEN] A Salesperson for the tasks
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] An Organizer task with date = WorkDate + 10
+        OrganizerTaskDate := WorkDate() + 10;
+        CreateOrganizerTaskForContact(OrganizerTodo, Contact, SalespersonPurchaser.Code, OrganizerTaskDate);
+
+        // [GIVEN] A Contact Attendee task with date = WorkDate + 5 (earlier)
+        AttendeeTaskDate := WorkDate() + 5;
+        CreateContactAttendeeTaskForContact(AttendeeTodo, Contact, SalespersonPurchaser.Code, AttendeeTaskDate);
+
+        // [WHEN] Calculate the Next Task Date FlowField on the Contact
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] The Next Task Date should equal the earlier date (Contact Attendee task date)
+        Assert.AreEqual(AttendeeTaskDate, Contact."Next Task Date", 'Next Task Date should return the minimum date from all task types');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateExcludesClosedTasks()
+    var
+        Contact: Record Contact;
+        Todo: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [FEATURE] [Contact] [Task]
+        // [SCENARIO] Next Task Date on Contact should exclude closed tasks
+        Initialize();
+
+        // [GIVEN] A Contact of type Company
+        LibraryMarketing.CreateCompanyContact(Contact);
+
+        // [GIVEN] A Salesperson for the task
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] A closed Organizer task linked to the Contact
+        TaskDate := WorkDate() + 5;
+        CreateOrganizerTaskForContact(Todo, Contact, SalespersonPurchaser.Code, TaskDate);
+        Todo.Validate(Closed, true);
+        Todo.Modify(true);
+
+        // [WHEN] Calculate the Next Task Date FlowField on the Contact
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] The Next Task Date should be empty (0D) because the only task is closed
+        Assert.AreEqual(0D, Contact."Next Task Date", 'Next Task Date should exclude closed tasks');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Contact Next Task Date");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Contact Next Task Date");
+
+        LibrarySales.SetCreditWarningsToNoWarnings();
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Contact Next Task Date");
+    end;
+
+    local procedure CreateOrganizerTaskForContact(var Todo: Record "To-do"; Contact: Record Contact; SalespersonCode: Code[20]; TaskDate: Date)
+    begin
+        Todo.Init();
+        Todo.Insert(true);
+        Todo.Validate(Type, Todo.Type::"Phone Call");
+        Todo.Validate(Date, TaskDate);
+        Todo.Validate("Salesperson Code", SalespersonCode);
+        Todo.Validate("Contact No.", Contact."No.");
+        Todo."Contact Company No." := Contact."No.";
+        Todo."System To-do Type" := Todo."System To-do Type"::Organizer;
+        Todo.Modify(true);
+    end;
+
+    local procedure CreateContactAttendeeTaskForContact(var Todo: Record "To-do"; Contact: Record Contact; SalespersonCode: Code[20]; TaskDate: Date)
+    begin
+        Todo.Init();
+        Todo.Insert(true);
+        Todo.Validate(Type, Todo.Type::"Phone Call");
+        Todo.Validate(Date, TaskDate);
+        Todo.Validate("Salesperson Code", SalespersonCode);
+        Todo.Validate("Contact No.", Contact."No.");
+        Todo."Contact Company No." := Contact."No.";
+        Todo."System To-do Type" := Todo."System To-do Type"::"Contact Attendee";
+        Todo.Modify(true);
+    end;
+}

