+codeunit 134424 "Issued Reminder Email Tests"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+    Permissions = TableData "Issued Reminder Header" = rimd,
+                  TableData "Issued Reminder Line" = rimd;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Issued Reminder] [Email]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Initialized: Boolean;
+        CustomerFoundInSourceTables: Boolean;
+        ExpectedCustomerSystemId: Guid;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailIncludesCustomerAsRelatedSource()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+    begin
+        // [SCENARIO 555555] When sending an issued reminder by email, the customer should be included as a related source
+        // This tests the fix for: "Issued reminder emails are not logged in sent e-mail history of a customer"
+        // The bug was that:
+        // 1. IsCustomerAccount did not include Database::"Issued Reminder Header"
+        // 2. Even if it did, the wrong field name 'Sell-to Customer No.' was used instead of 'Customer No.'
+        Initialize();
+
+        // [GIVEN] A customer with an issued reminder
+        LibrarySales.CreateCustomer(Customer);
+        Customer."E-Mail" := 'test@example.com';
+        Customer.Modify();
+        CreateIssuedReminderForCustomer(IssuedReminderHeader, Customer."No.");
+
+        // Store expected customer SystemId for verification in event subscriber
+        ExpectedCustomerSystemId := Customer.SystemId;
+        CustomerFoundInSourceTables := false;
+
+        // Setup report selection for reminders
+        ReportSelections.SetRange(Usage, ReportSelections.Usage::Reminder);
+        ReportSelections.DeleteAll();
+        ReportSelections.Init();
+        ReportSelections.Usage := ReportSelections.Usage::Reminder;
+        ReportSelections.Sequence := '1';
+        ReportSelections."Report ID" := Report::Reminder;
+        ReportSelections."Use for Email Attachment" := true;
+        ReportSelections.Insert();
+        Commit();
+
+        // [WHEN] The email sending process prepares source tables for the issued reminder
+        // We bind to the OnSendEmailDirectlyOnBeforeSend event to capture the source tables list
+        // The event subscriber will set IsHandled to true to prevent actual email sending
+        BindSubscription(Codeunit::"Issued Reminder Email Tests");
+
+        // Call SendEmailToCust which internally calls SendEmailDirectly
+        // The event subscriber will verify the source tables and stop further processing
+        IssuedReminderHeader.SetRecFilter();
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Test Reminder',
+            true,
+            Customer."No.");
+
+        UnbindSubscription(Codeunit::"Issued Reminder Email Tests");
+
+        // [THEN] The customer should be included in the source tables list as a related source
+        Assert.IsTrue(CustomerFoundInSourceTables, 'Customer should be included in source tables for email history tracking');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Issued Reminder Email Tests");
+
+        LibraryVariableStorage.Clear();
+
+        if Initialized then
+            exit;
+
+        Initialized := true;
+        Commit();
+    end;
+
+    local procedure CreateIssuedReminderForCustomer(var IssuedReminderHeader: Record "Issued Reminder Header"; CustomerNo: Code[20])
+    var
+        IssuedReminderLine: Record "Issued Reminder Line";
+        CustomerPostingGroup: Record "Customer Posting Group";
+    begin
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup);
+        CustomerPostingGroup."Additional Fee Account" := '';
+        CustomerPostingGroup.Modify();
+
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." := LibraryUtility.GenerateRandomCode(IssuedReminderHeader.FieldNo("No."), DATABASE::"Issued Reminder Header");
+        IssuedReminderHeader."Customer No." := CustomerNo;
+        IssuedReminderHeader."Customer Posting Group" := CustomerPostingGroup.Code;
+        IssuedReminderHeader."Due Date" := WorkDate() + 30;
+        IssuedReminderHeader.Insert();
+
+        IssuedReminderLine.Init();
+        IssuedReminderLine."Line No." := 10000;
+        IssuedReminderLine."Line Type" := IssuedReminderLine."Line Type"::"Reminder Line";
+        IssuedReminderLine."Reminder No." := IssuedReminderHeader."No.";
+        IssuedReminderLine."Due Date" := IssuedReminderHeader."Due Date";
+        IssuedReminderLine."Remaining Amount" := 100;
+        IssuedReminderLine.Amount := 100;
+        IssuedReminderLine.Type := IssuedReminderLine.Type::"G/L Account";
+        IssuedReminderLine.Insert();
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", OnSendEmailDirectlyOnBeforeSend, '', false, false)]
+    local procedure OnSendEmailDirectlyOnBeforeSendHandler(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    var
+        i: Integer;
+    begin
+        // Verify that Database::Customer is in the SourceTableIDs list
+        // and that the corresponding SourceID matches our expected customer SystemId
+        for i := 1 to SourceTableIDs.Count() do
+            if SourceTableIDs.Get(i) = Database::Customer then
+                if SourceIDs.Get(i) = ExpectedCustomerSystemId then begin
+                    CustomerFoundInSourceTables := true;
+                    break;
+                end;
+
+        // Set IsHandled to true to prevent actual email sending
+        // This is sufficient for our test - we just need to verify the source tables
+        AllEmailsWereSuccessful := true;
+        IsHandled := true;
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", OnBeforeGetEmailBodyCustomer, '', false, false)]
+    local procedure OnBeforeGetEmailBodyCustomerHandler(ReportUsage: Integer; RecordVariant: Variant; var TempBodyReportSelections: Record "Report Selections" temporary; CustNo: Code[20]; var CustEmailAddress: Text[250]; var EmailBodyText: Text; var IsHandled: Boolean; var Result: Boolean)
+    begin
+        // Skip email body generation to avoid report execution
+        IsHandled := true;
+        Result := false;
+    end;
+}

