+    [Scope('OnPrem')]
+    procedure ReopenCreatedDocWithExistingRelatedRecordKeepsStatusCreated()
+    var
+        IncomingDocument: Record "Incoming Document";
+        PurchaseHeader: Record "Purchase Header";
+        ReleaseIncomingDocument: Codeunit "Release Incoming Document";
+    begin
+        // [SCENARIO] When reopening an Incoming Document with status "Created" that has an existing related document,
+        // the status should remain "Created" instead of changing to "New".
+        // [GIVEN] An incoming document in Created status linked to an existing Purchase Invoice
+        PurchaseHeader.SetFilter("Incoming Document Entry No.", '<>0');
+        PurchaseHeader.DeleteAll();
+
+        CreateNewIncomingDocument(IncomingDocument);
+        IncomingDocument.Release();
+        IncomingDocument.Modify();
+        IncomingDocument.CreatePurchInvoice();
+        IncomingDocument.Modify();
+
+        // Verify document was created and status is Created
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+        IncomingDocument.TestField("Document Type", IncomingDocument."Document Type"::"Purchase Invoice");
