+        IncomingDocument.Get(IncomingDocument."Entry No.");
+        IncomingDocument.TestField(Status, IncomingDocument.Status::Created);
+
+        // [WHEN] Reopen is called on the incoming document
+        ReleaseIncomingDocument.Reopen(IncomingDocument);
+
+        // [THEN] Status should remain "Created" because the related record (Purchase Invoice) still exists
