+codeunit 134399 "Bill-to Contact Info Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('CustomerLookupHandler,ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure BillToContactInfoUpdatesOnCustomerLookup()
+    var
+        Customer1: Record Customer;
+        Customer2: Record Customer;
+        Contact1: Record Contact;
+        Contact2: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        SalesHeader: Record "Sales Header";
+        SalesInvoice: TestPage "Sales Invoice";
+        PhoneNo1: Text[30];
+        PhoneNo2: Text[30];
+        MobilePhoneNo1: Text[30];
+        MobilePhoneNo2: Text[30];
+        Email1: Text[80];
+        Email2: Text[80];
+    begin
+        // [FEATURE] [Sales Invoice] [Bill-to] [Contact Info]
+        // [SCENARIO 000001] When selecting a different Bill-to Customer via lookup, the Bill-to Contact phone numbers and email should update to the new contact's values.
+        Initialize();
+
+        // [GIVEN] Customer 1 with Contact 1 having Phone No. "111", Mobile Phone No. "222", Email "contact1@test.com"
+        CreateCustomerWithPrimaryContact(Customer1, Contact1);
+        PhoneNo1 := '111-1111111';
+        MobilePhoneNo1 := '222-2222222';
+        Email1 := 'contact1@test.com';
+        Contact1."Phone No." := PhoneNo1;
+        Contact1."Mobile Phone No." := MobilePhoneNo1;
+        Contact1."E-Mail" := Email1;
+        Contact1.Modify(true);
+
+        // [GIVEN] Customer 2 with Contact 2 having Phone No. "333", Mobile Phone No. "444", Email "contact2@test.com"
+        CreateCustomerWithPrimaryContact(Customer2, Contact2);
+        PhoneNo2 := '333-3333333';
+        MobilePhoneNo2 := '444-4444444';
+        Email2 := 'contact2@test.com';
+        Contact2."Phone No." := PhoneNo2;
+        Contact2."Mobile Phone No." := MobilePhoneNo2;
+        Contact2."E-Mail" := Email2;
+        Contact2.Modify(true);
+
+        // [GIVEN] A Sales Invoice with Customer 1 as Sell-to and Bill-to Customer
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer1."No.");
+
+        // [GIVEN] Sales Invoice page is opened with Bill-to = "Another Customer"
+        LibraryVariableStorage.Enqueue(Customer2."No."); // For CustomerLookupHandler to select Customer2
+        SalesInvoice.OpenEdit();
+        SalesInvoice.FILTER.SetFilter("No.", SalesHeader."No.");
+
+        // [WHEN] User looks up Bill-to Name and selects Customer 2
+        SalesInvoice."Bill-to Name".Lookup();
+
+        // [THEN] Bill-to Customer No. is updated to Customer 2
+        SalesHeader.Find();
+        SalesHeader.TestField("Bill-to Customer No.", Customer2."No.");
+
+        // [THEN] Bill-to Contact info should be updated to Contact 2's values
+        // The page should display the new contact's phone numbers and email
+        Assert.AreEqual(PhoneNo2, SalesInvoice.BillToContactPhoneNo.Value, 'Bill-to Contact Phone No. should be updated');
+        Assert.AreEqual(MobilePhoneNo2, SalesInvoice.BillToContactMobilePhoneNo.Value, 'Bill-to Contact Mobile Phone No. should be updated');
+        Assert.AreEqual(Email2, SalesInvoice.BillToContactEmail.Value, 'Bill-to Contact Email should be updated');
+
+        SalesInvoice.Close();
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    [Test]
+    [HandlerFunctions('CustomerLookupHandler,ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure SalesOrderBillToContactInfoUpdatesOnCustomerLookup()
+    var
+        Customer1: Record Customer;
+        Customer2: Record Customer;
+        Contact1: Record Contact;
+        Contact2: Record Contact;
+        SalesHeader: Record "Sales Header";
+        SalesOrder: TestPage "Sales Order";
+        PhoneNo2: Text[30];
+        MobilePhoneNo2: Text[30];
+        Email2: Text[80];
+    begin
+        // [FEATURE] [Sales Order] [Bill-to] [Contact Info]
+        // [SCENARIO 000002] When selecting a different Bill-to Customer via lookup on Sales Order, the Bill-to Contact phone numbers and email should update.
+        Initialize();
+
+        // [GIVEN] Customer 1 with Contact 1
+        CreateCustomerWithPrimaryContact(Customer1, Contact1);
+        Contact1."Phone No." := '111-1111111';
+        Contact1."Mobile Phone No." := '222-2222222';
+        Contact1."E-Mail" := 'contact1@test.com';
+        Contact1.Modify(true);
+
+        // [GIVEN] Customer 2 with Contact 2 having different phone numbers and email
+        CreateCustomerWithPrimaryContact(Customer2, Contact2);
+        PhoneNo2 := '333-3333333';
+        MobilePhoneNo2 := '444-4444444';
+        Email2 := 'contact2@test.com';
+        Contact2."Phone No." := PhoneNo2;
+        Contact2."Mobile Phone No." := MobilePhoneNo2;
+        Contact2."E-Mail" := Email2;
+        Contact2.Modify(true);
+
+        // [GIVEN] A Sales Order with Customer 1 as Sell-to and Bill-to Customer
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer1."No.");
+
+        // [GIVEN] Sales Order page is opened
+        LibraryVariableStorage.Enqueue(Customer2."No.");
+        SalesOrder.OpenEdit();
+        SalesOrder.FILTER.SetFilter("No.", SalesHeader."No.");
+
+        // [WHEN] User looks up Bill-to Name and selects Customer 2
+        SalesOrder."Bill-to Name".Lookup();
+
+        // [THEN] Bill-to Contact info should be updated to Contact 2's values
+        Assert.AreEqual(PhoneNo2, SalesOrder.BillToContactPhoneNo.Value, 'Bill-to Contact Phone No. should be updated');
+        Assert.AreEqual(MobilePhoneNo2, SalesOrder.BillToContactMobilePhoneNo.Value, 'Bill-to Contact Mobile Phone No. should be updated');
