diff --git a/App/Layers/W1/Tests/SCM/SCMReservEntryRounding.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMReservEntryRounding.Codeunit.al
new file mode 100644
index 00000000..b234f9dc
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReservEntryRounding.Codeunit.al
@@ -0,0 +1,199 @@
+codeunit 137276 "SCM Reserv. Entry Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation] [Tracking] [Rounding] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        isInitialized: Boolean;
+        QuantitySumErr: Label 'The sum of Quantity in Reservation Entries should be %1, but was %2.';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TrackingSplitQuantityRoundsCorrectlyWithFix()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ReservationEntry: Record "Reservation Entry";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        UnitOfMeasure: Record "Unit of Measure";
+        QtyPerUOM: Decimal;
+        ExpectedQuantity: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Tracking] [Rounding]
+        // [SCENARIO] When tracking entries are split into 3, each with a base quantity that creates
+        // repeating decimals when divided by Qty per UOM, the total Quantity should round correctly
+        // instead of accumulating to x.00001 error.
+        // This tests the fix where CalcReservationQuantity now includes tracking entries in the filter
+        // to properly calculate the total and distribute rounding.
+
+        // [GIVEN] An item with Order Tracking Policy = "Tracking & Action Msg."
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Order Tracking Policy", Item."Order Tracking Policy"::"Tracking & Action Msg.");
+        Item.Modify(true);
+
+        // [GIVEN] Item has a Sales Unit of Measure with Qty. per Unit of Measure = 24 (e.g., CASE = 24 PCS)
+        QtyPerUOM := 24;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] A Sales Order for 12 CASES (= 288 pcs in base UOM)
+        ExpectedQuantity := 12;
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", ExpectedQuantity);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Create three tracking entries that simulate the split scenario from the issue
+        // The base quantities 13, 137, and 138 sum to 288 (= 12 CASES)
+        // Without the fix, each entry's Quantity would be calculated independently:
+        // - 13/24 = 0.54167, 137/24 = 5.70833, 138/24 = 5.75 = Total 12.00000
+        // With the fix, CalcReservationQuantity considers existing tracking entries when inserting
+        // each new one, ensuring the total rounds correctly.
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -13, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -137, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -138, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+
+        // [WHEN] We sum up the Quantity field of all tracking reservation entries
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Source ID", SalesLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLine."Line No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Tracking);
+        ReservationEntry.CalcSums(Quantity);
+        TotalQuantity := ReservationEntry.Quantity;
+
+        // [THEN] The sum of Quantity should equal the expected quantity (12 CASES, negative for demand)
+        Assert.AreEqual(-ExpectedQuantity, TotalQuantity, StrSubstNo(QuantitySumErr, -ExpectedQuantity, TotalQuantity));
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ThreeTrackingEntriesEndingIn7RoundCorrectly()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ReservationEntry: Record "Reservation Entry";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        UnitOfMeasure: Record "Unit of Measure";
+        QtyPerUOM: Decimal;
+        ExpectedQuantity: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Tracking] [Rounding]
+        // [SCENARIO] When tracking entries are split into 3, each ending in x.xxxx7 after division,
+        // the total should round correctly instead of accumulating to x.00001 error.
+        // Per issue: "tracking lines are split into 3, each ending in x.xxxx7"
+
+        // [GIVEN] An item with Order Tracking Policy
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Order Tracking Policy", Item."Order Tracking Policy"::"Tracking & Action Msg.");
+        Item.Modify(true);
+
+        // [GIVEN] Item has a Sales Unit of Measure with Qty. per Unit of Measure = 24
+        QtyPerUOM := 24;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] A Sales Order for 12 CASES (= 288 pcs in base UOM)
+        ExpectedQuantity := 12;
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", ExpectedQuantity);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Three tracking entries with base quantities that when divided by 24 
+        // produce values ending in 7 (repeating decimals that round to .xxxx7)
+        // 1/24 = 0.04166666... rounds to 0.04167
+        // 143/24 = 5.958333... rounds to 5.95833  
+        // 144/24 = 6.0
+        // These quantities create potential rounding accumulation
+        // We use: 1 + 143 + 144 = 288 = 12 CASES
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -1, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -143, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+        CreateTrackingReservEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -144, QtyPerUOM, ReservationEntry."Reservation Status"::Tracking);
+
+        // [WHEN] We sum up the Quantity field of all tracking reservation entries
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Source ID", SalesLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLine."Line No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Tracking);
+        ReservationEntry.CalcSums(Quantity);
+        TotalQuantity := ReservationEntry.Quantity;
+
+        // [THEN] The sum of Quantity should be exactly -12 (12 CASES), not -12.00001
+        Assert.AreEqual(-ExpectedQuantity, TotalQuantity, StrSubstNo(QuantitySumErr, -ExpectedQuantity, TotalQuantity));
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Reserv. Entry Rounding");
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Reserv. Entry Rounding");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Reserv. Entry Rounding");
+    end;
+
+    local procedure CreateTrackingReservEntry(var ReservationEntry: Record "Reservation Entry"; ItemNo: Code[20]; SourceID: Code[20]; SourceRefNo: Integer; QtyBase: Decimal; QtyPerUOM: Decimal; ReservStatus: Enum "Reservation Status")
+    var
+        LastEntryNo: Integer;
+    begin
+        ReservationEntry.Reset();
+        if ReservationEntry.FindLast() then
+            LastEntryNo := ReservationEntry."Entry No.";
+
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := LastEntryNo + 1;
+        ReservationEntry."Item No." := ItemNo;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservStatus;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Positive := QtyBase > 0;
+        ReservationEntry."Creation Date" := WorkDate();
+        ReservationEntry.Validate("Quantity (Base)", QtyBase);
+        ReservationEntry.Insert(true);
+    end;
+}
\ No newline at end of file

