diff --git a/App/Layers/W1/Tests/SCM/SCMPlanReqWkshtReservation.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMPlanReqWkshtReservation.Codeunit.al
new file mode 100644
index 00000000..731ebf38
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMPlanReqWkshtReservation.Codeunit.al
@@ -0,0 +1,270 @@
+codeunit 137100 "SCM Plan-Req. Wksht Reserv."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Requisition Worksheet] [Reservation Entry] [Item Tracking] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        OriginalQtyOnPurchLineErr: Label 'Purchase line quantity should not change after recalculating the requisition worksheet.';
+        ReservationEntrySurplusCountErr: Label 'Number of surplus reservation entries for purchase line should not change after recalculating the requisition worksheet.';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecalcReqWorksheetDoesNotCreateDuplicateSurplusReservationEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseLine: Record "Purchase Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        LotNo: Code[50];
+        SalesQuantity: Decimal;
+        PurchaseQuantity: Decimal;
+        SurplusQuantity: Decimal;
+        SurplusCountBefore: Integer;
+        SurplusCountAfter: Integer;
+    begin
+        // [SCENARIO] When recalculating a requisition worksheet with no planning results (Planning Flexibility = None),
+        // surplus reservation entries should not be duplicated on the purchase line.
+
+        // [GIVEN] Initialize and create item with Lot Tracking, Replenishment = Purchase, Reordering Policy = Lot-for-Lot
+        Initialize();
+        SalesQuantity := 100;
+        PurchaseQuantity := 150;
+        SurplusQuantity := PurchaseQuantity - SalesQuantity;
+
+        CreateLotTrackedItemWithLotForLotPolicy(Item);
+
+        // [GIVEN] Create a Sales Order for 100 PCS of the item
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQuantity);
+
+        // [GIVEN] Calculate Plan in Requisition Worksheet - this creates a requisition line for 100 PCS
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Find the requisition line and modify:
+        // - Increase Quantity from 100 to 150 (creating a surplus of 50)
+        // - Set Planning Flexibility = None (so recalculation won't affect it)
+        // - Set Vendor No.
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, PurchaseQuantity);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Create item tracking (lot number) on the requisition line for the full quantity
+        LotNo := LibraryUtility.GenerateGUID();
+        CreateRequisitionLineItemTracking(RequisitionLine, LotNo, PurchaseQuantity);
+
+        // [GIVEN] Accept Action Message and Carry Out to create the Purchase Order
+        RequisitionLine."Accept Action Message" := true;
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Find the created Purchase Order and verify initial state
+        FindPurchaseLine(PurchaseLine, Item."No.");
+        Assert.AreEqual(PurchaseQuantity, PurchaseLine.Quantity, 'Purchase line should have quantity 150');
+
+        // [GIVEN] Count surplus reservation entries for the purchase line before recalculation
+        SurplusCountBefore := CountSurplusReservationEntriesForPurchaseLine(PurchaseLine);
+
+        // [WHEN] Recalculate the requisition worksheet for the same item
+        // Since Planning Flexibility = None on the PO, no new requisition lines should be created
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [THEN] The Purchase Line quantity should remain unchanged
+        PurchaseLine.Get(PurchaseLine."Document Type", PurchaseLine."Document No.", PurchaseLine."Line No.");
+        Assert.AreEqual(PurchaseQuantity, PurchaseLine.Quantity, OriginalQtyOnPurchLineErr);
+
+        // [THEN] The number of surplus reservation entries should not increase
+        SurplusCountAfter := CountSurplusReservationEntriesForPurchaseLine(PurchaseLine);
+        Assert.AreEqual(SurplusCountBefore, SurplusCountAfter, ReservationEntrySurplusCountErr);
+
+        // [THEN] Verify the surplus quantity on reservation entries is still correct (should be 50, not 100 or more)
+        VerifySurplusReservationEntryQuantity(PurchaseLine, SurplusQuantity);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecalcReqWorksheetMultipleTimesDoesNotAccumulateSurplus()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseLine: Record "Purchase Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        LotNo: Code[50];
+        SalesQuantity: Decimal;
+        PurchaseQuantity: Decimal;
+        SurplusQuantity: Decimal;
+        SurplusCountAfterFirstRecalc: Integer;
+        SurplusCountAfterSecondRecalc: Integer;
+        SurplusCountAfterThirdRecalc: Integer;
+    begin
+        // [SCENARIO] When recalculating a requisition worksheet multiple times, 
+        // surplus reservation entries should not accumulate.
+
+        // [GIVEN] Initialize and create item with Lot Tracking, Replenishment = Purchase, Reordering Policy = Lot-for-Lot
+        Initialize();
+        SalesQuantity := 100;
+        PurchaseQuantity := 150;
+        SurplusQuantity := PurchaseQuantity - SalesQuantity;
+
+        CreateLotTrackedItemWithLotForLotPolicy(Item);
+
+        // [GIVEN] Create a Sales Order
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQuantity);
+
+        // [GIVEN] Calculate Plan, modify requisition line, and carry out to create Purchase Order
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, PurchaseQuantity);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        LotNo := LibraryUtility.GenerateGUID();
+        CreateRequisitionLineItemTracking(RequisitionLine, LotNo, PurchaseQuantity);
+
+        RequisitionLine."Accept Action Message" := true;
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        FindPurchaseLine(PurchaseLine, Item."No.");
+
+        // [WHEN] Recalculate the requisition worksheet 3 times
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+        SurplusCountAfterFirstRecalc := CountSurplusReservationEntriesForPurchaseLine(PurchaseLine);
+
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+        SurplusCountAfterSecondRecalc := CountSurplusReservationEntriesForPurchaseLine(PurchaseLine);
+
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+        SurplusCountAfterThirdRecalc := CountSurplusReservationEntriesForPurchaseLine(PurchaseLine);
+
+        // [THEN] The surplus entry count should remain the same after each recalculation
+        Assert.AreEqual(SurplusCountAfterFirstRecalc, SurplusCountAfterSecondRecalc, 
+            'Surplus entries should not increase between 1st and 2nd recalculation');
+        Assert.AreEqual(SurplusCountAfterSecondRecalc, SurplusCountAfterThirdRecalc, 
+            'Surplus entries should not increase between 2nd and 3rd recalculation');
+
+        // [THEN] Verify surplus quantity is still correct (should be 50, not accumulated to 150 or more)
+        VerifySurplusReservationEntryQuantity(PurchaseLine, SurplusQuantity);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Plan-Req. Wksht Reserv.");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Plan-Req. Wksht Reserv.");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Plan-Req. Wksht Reserv.");
+    end;
+
+    local procedure CreateLotTrackedItemWithLotForLotPolicy(var Item: Record Item)
+    var
+        LotAccumulationPeriod: DateFormula;
+    begin
+        LibraryInventory.CreateItem(Item);
+        LibraryItemTracking.AddLotNoTrackingInfo(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Evaluate(LotAccumulationPeriod, '<0D>');
+        Item.Validate("Lot Accumulation Period", LotAccumulationPeriod);
+        Item.Modify(true);
+    end;
+
+    local procedure CalculatePlanForRequisitionWorksheet(var RequisitionWkshName: Record "Requisition Wksh. Name"; Item: Record Item; StartDate: Date; EndDate: Date)
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+    begin
+        ReqWkshTemplate.SetRange(Type, ReqWkshTemplate.Type::"Req.");
+        ReqWkshTemplate.FindFirst();
+        if RequisitionWkshName.Name = '' then
+            LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+        LibraryPlanning.CalculatePlanForReqWksh(Item, ReqWkshTemplate.Name, RequisitionWkshName.Name, StartDate, EndDate);
+    end;
+
+    local procedure SelectRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.FindFirst();
+    end;
+
+    local procedure CreateRequisitionLineItemTracking(RequisitionLine: Record "Requisition Line"; LotNo: Code[50]; Quantity: Decimal)
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryItemTracking.CreateReqWkshItemTracking(ReservationEntry, RequisitionLine, '', LotNo, Quantity);
+    end;
+
+    local procedure FindPurchaseLine(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    begin
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", ItemNo);
+        PurchaseLine.FindFirst();
+    end;
+
+    local procedure CountSurplusReservationEntriesForPurchaseLine(PurchaseLine: Record "Purchase Line"): Integer
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line",
+            PurchaseLine."Document Type".AsInteger(),
+            PurchaseLine."Document No.",
+            PurchaseLine."Line No.",
+            true);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        exit(ReservationEntry.Count);
+    end;
+
+    local procedure VerifySurplusReservationEntryQuantity(PurchaseLine: Record "Purchase Line"; ExpectedSurplusQuantity: Decimal)
+    var
+        ReservationEntry: Record "Reservation Entry";
+        TotalSurplusQuantity: Decimal;
+    begin
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line",
+            PurchaseLine."Document Type".AsInteger(),
+            PurchaseLine."Document No.",
+            PurchaseLine."Line No.",
+            true);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        if ReservationEntry.FindSet() then
+            repeat
+                TotalSurplusQuantity += ReservationEntry.Quantity;
+            until ReservationEntry.Next() = 0;
+
+        Assert.AreEqual(
+            ExpectedSurplusQuantity,
+            TotalSurplusQuantity,
+            'Total surplus quantity on reservation entries should match expected surplus');
+    end;
+}

