+codeunit 134291 "ERM VAT Settl. Jnl Tmpl Mand."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [VAT Settlement] [Journal Template Name Mandatory]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcAndPostVATSettlementWithJnlTemplNameMandatory()
+    var
+        GenJournalLine: Record "Gen. Journal Line";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        CalcandPostVATSettlement: Report "Calc. and Post VAT Settlement";
+        DocumentNo: Code[20];
+        SettlementAccountNo: Code[20];
+    begin
+        // [SCENARIO] Calculate and Post VAT Settlement should not fail when "Journal Templ. Name Mandatory" is enabled in G/L Setup
+        // [GIVEN] G/L Setup with "Journal Templ. Name Mandatory" enabled
+        Initialize();
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup."Journal Templ. Name Mandatory" := true;
+        GeneralLedgerSetup.Modify();
+        Commit();
+
+        // [GIVEN] VAT Posting Setup with VAT accounts
+        LibraryERM.CreateVATPostingSetupWithAccounts(
+          VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT", LibraryRandom.RandInt(10));
+
+        // [GIVEN] Posted General Journal Line with VAT
+        LibraryERM.SelectGenJnlBatch(GenJournalBatch);
+        LibraryERM.ClearGenJournalLines(GenJournalBatch);
+        LibraryERM.CreateGeneralJnlLine(
+          GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+          GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+          LibraryERM.CreateGLAccountWithVATPostingSetup(VATPostingSetup, GenJournalLine."Gen. Posting Type"::Sale),
+          LibraryRandom.RandDec(1000, 2));
+        DocumentNo := GenJournalLine."Document No.";
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [GIVEN] Settlement G/L Account
+        SettlementAccountNo := LibraryERM.CreateGLAccountNo();
+
+        // [WHEN] Run Calc. and Post VAT Settlement with Post enabled
+        Clear(CalcandPostVATSettlement);
+        VATPostingSetup.SetRange("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        VATPostingSetup.SetRange("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        CalcandPostVATSettlement.SetTableView(VATPostingSetup);
+        CalcandPostVATSettlement.InitializeRequest(
+          WorkDate(), WorkDate(), WorkDate(), DocumentNo, SettlementAccountNo, false, true);
+        CalcandPostVATSettlement.UseRequestPage(false);
+        CalcandPostVATSettlement.Run();
+
+        // [THEN] No error occurs (previously "Journal Template Name must have a value" error would occur)
+        // [THEN] VAT Settlement is posted successfully - verify VAT Entry with settlement amount exists
+        VerifyVATSettlementEntry(DocumentNo);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM VAT Settl. Jnl Tmpl Mand.");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM VAT Settl. Jnl Tmpl Mand.");
+        LibraryERMCountryData.CreateVATData();
+
+        LibrarySetupStorage.Save(Database::"General Ledger Setup");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM VAT Settl. Jnl Tmpl Mand.");
+    end;
+
+    local procedure VerifyVATSettlementEntry(DocumentNo: Code[20])
+    var
+        VATEntry: Record "VAT Entry";
+    begin
+        VATEntry.SetRange("Document No.", DocumentNo);
+        VATEntry.SetRange(Closed, true);
+        Assert.RecordIsNotEmpty(VATEntry);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMTransferGetReceiptLines.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMTransferGetReceiptLines.Codeunit.al
