+codeunit 137933 "SCM Transfer Get Receipt Lines"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Transfer Order] [Get Receipt Lines]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesFiltersByLineLocationCode()
+    var
+        Item: Record Item;
+        Location: array[3] of Record Location;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+    begin
+        // [FEATURE] [UI]
+        // [SCENARIO] Function "Get Receipt Lines" filters by line location code, not header location code
+        // [SCENARIO] When a Purchase Order has location code only on the line (not header),
+        // [SCENARIO] the Posted Purchase Receipt should be shown in Get Receipt Lines
+        Initialize();
+
+        // [GIVEN] 3 locations: LOC1 (transfer from), LOC2 (transfer to), and TRANSIT
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[1]);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[2]);
+        LibraryWarehouse.CreateInTransitLocation(Location[3]);
+
+        // [GIVEN] Create an item with FIFO costing method
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create Purchase Order without location code on header
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+        // Note: NOT setting PurchaseHeader."Location Code" - this is the key scenario
+
+        // [GIVEN] Create Purchase Line with location code "LOC1" on line only
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item,
+            Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        PurchaseLine.Validate("Location Code", Location[1].Code);
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        PurchaseLine.Modify(true);
+
+        // [GIVEN] Post Purchase Order to create a receipt
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // [GIVEN] Find the Posted Purchase Receipt (header has NO location code, line has LOC1)
+        PurchRcptHeader.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptHeader.FindLast();
+        Assert.AreEqual('', PurchRcptHeader."Location Code", 'Receipt header should have empty location code');
+
+        PurchRcptLine.SetRange("Document No.", PurchRcptHeader."No.");
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+        Assert.AreEqual(Location[1].Code, PurchRcptLine."Location Code", 'Receipt line should have location LOC1');
+
+        // [GIVEN] Create transfer order from location "LOC1" to "LOC2"
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, Location[1].Code, Location[2].Code, Location[3].Code);
+
+        // [WHEN] Run function "Get Receipt Lines" and select the receipt
+        LibraryVariableStorage.Enqueue(PurchRcptHeader."No."); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(PurchRcptLine."No."); // Purchase Receipt Line to select
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created from the receipt line (receipt was shown despite header having no location)
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        Assert.IsTrue(TransferLine.FindFirst(), 'Transfer line should be created');
+        TransferLine.TestField("Item No.", Item."No.");
+        TransferLine.TestField(Quantity, PurchRcptLine.Quantity);
+    end;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesSetsApplToItemEntry()
+    var
+        Item: Record Item;
+        Location: array[3] of Record Location;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+    begin
+        // [FEATURE] [UI] [Item Application]
+        // [SCENARIO] Function "Get Receipt Lines" sets "Appl.-to Item Entry" on transfer line
+        // [SCENARIO] This ensures the correct item ledger entry is applied during transfer
+        Initialize();
+
+        // [GIVEN] 3 locations: LOC1 (transfer from), LOC2 (transfer to), and TRANSIT
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[1]);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[2]);
+        LibraryWarehouse.CreateInTransitLocation(Location[3]);
+
+        // [GIVEN] Create an item with FIFO costing method
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create and post Purchase Order with location on header
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+        PurchaseHeader.Validate("Location Code", Location[1].Code);
+        PurchaseHeader.Modify(true);
+
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item,
+            Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        PurchaseLine.Modify(true);
+
+        // [GIVEN] Post Purchase Order to create a receipt
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // [GIVEN] Find the Posted Purchase Receipt
+        PurchRcptHeader.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptHeader.FindLast();
+
+        PurchRcptLine.SetRange("Document No.", PurchRcptHeader."No.");
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+
+        // [GIVEN] Find the Item Ledger Entry created by the receipt
+        ItemLedgerEntry.SetRange("Document No.", PurchRcptHeader."No.");
+        ItemLedgerEntry.SetRange("Document Type", ItemLedgerEntry."Document Type"::"Purchase Receipt");
+        ItemLedgerEntry.SetRange("Document Line No.", PurchRcptLine."Line No.");
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create transfer order from location "LOC1" to "LOC2"
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, Location[1].Code, Location[2].Code, Location[3].Code);
+
+        // [WHEN] Run function "Get Receipt Lines" and select the receipt line
+        LibraryVariableStorage.Enqueue(PurchRcptHeader."No."); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(PurchRcptLine."No."); // Purchase Receipt Line to select
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with "Appl.-to Item Entry" set to the item ledger entry
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        Assert.IsTrue(TransferLine.FindFirst(), 'Transfer line should be created');
+        TransferLine.TestField("Item No.", Item."No.");
+        TransferLine.TestField("Appl.-to Item Entry", ItemLedgerEntry."Entry No.");
+    end;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesAppliesCorrectCostEntry()
+    var
+        Item: Record Item;
+        Location: array[3] of Record Location;
+        PurchaseHeader: array[3] of Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        DirectUnitCost: array[3] of Decimal;
+        PurchReceiptNo: array[3] of Code[20];
+        i: Integer;
+    begin
+        // [FEATURE] [UI] [Item Application] [Costing]
+        // [SCENARIO] When selecting a specific purchase receipt line in "Get Receipt Lines",
+        // [SCENARIO] the transfer line should be linked to the correct item ledger entry with correct cost
+        Initialize();
+
+        // [GIVEN] 3 locations: LOC1 (transfer from), LOC2 (transfer to), and TRANSIT
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[1]);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location[2]);
+        LibraryWarehouse.CreateInTransitLocation(Location[3]);
+
+        // [GIVEN] Create an item with FIFO costing method
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create 3 purchase orders with different unit costs and post them
+        DirectUnitCost[1] := 100;
+        DirectUnitCost[2] := 120;
+        DirectUnitCost[3] := 130;
+
+        for i := 1 to 3 do begin
+            LibraryPurchase.CreatePurchHeader(PurchaseHeader[i], PurchaseHeader[i]."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+            PurchaseHeader[i].Validate("Location Code", Location[1].Code);
+            PurchaseHeader[i].Modify(true);
+
+            LibraryPurchase.CreatePurchaseLine(
+                PurchaseLine, PurchaseHeader[i], PurchaseLine.Type::Item,
+                Item."No.", 10); // Quantity 10 for all
+            PurchaseLine.Validate("Direct Unit Cost", DirectUnitCost[i]);
+            PurchaseLine.Modify(true);
+
+            LibraryPurchase.PostPurchaseDocument(PurchaseHeader[i], true, false);
+
+            PurchRcptHeader.SetRange("Buy-from Vendor No.", PurchaseHeader[i]."Buy-from Vendor No.");
+            PurchRcptHeader.FindLast();
+            PurchReceiptNo[i] := PurchRcptHeader."No.";
+        end;
+
+        // [GIVEN] Get the LAST (newest) receipt with cost 130
+        PurchRcptHeader.Get(PurchReceiptNo[3]);
+        PurchRcptLine.SetRange("Document No.", PurchRcptHeader."No.");
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+
+        // [GIVEN] Find the Item Ledger Entry for the LAST receipt (cost 130)
+        ItemLedgerEntry.SetRange("Document No.", PurchRcptHeader."No.");
+        ItemLedgerEntry.SetRange("Document Type", ItemLedgerEntry."Document Type"::"Purchase Receipt");
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create transfer order from location "LOC1" to "LOC2"
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, Location[1].Code, Location[2].Code, Location[3].Code);
+
+        // [WHEN] Run function "Get Receipt Lines" and select the LAST (newest) receipt
+        LibraryVariableStorage.Enqueue(PurchReceiptNo[3]); // Select the last receipt with cost 130
+        LibraryVariableStorage.Enqueue(Item."No."); // Purchase Receipt Line to select
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with "Appl.-to Item Entry" pointing to the LAST receipt's entry
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        Assert.IsTrue(TransferLine.FindFirst(), 'Transfer line should be created');
+        TransferLine.TestField("Item No.", Item."No.");
+        TransferLine.TestField("Appl.-to Item Entry", ItemLedgerEntry."Entry No.");
+
+        // [THEN] The applied item ledger entry is from the last receipt (not FIFO order)
+        ItemLedgerEntry.Get(TransferLine."Appl.-to Item Entry");
+        Assert.AreEqual(PurchReceiptNo[3], ItemLedgerEntry."Document No.", 'Should apply to the selected receipt, not FIFO');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Transfer Get Receipt Lines");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
