@@ -0,0 +1,84 @@
+codeunit 134290 "Non-Ded. VAT Unit Cost Zero"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non-Deductible VAT]
+    end;
+
+    var
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    procedure NonDeductibleVATClearedWhenDirectUnitCostSetToZero()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchHeader: Record "Purchase Header";
+        PurchLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] When changing the Direct Unit Cost to 0 in a purchase invoice line, the Non-Deductible VAT amounts are cleared
+        // [FEATURE] [Purchase] [Non-Deductible VAT]
+
+        Initialize();
+
+        // [GIVEN] VAT Posting Setup with Non-Deductible VAT enabled
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] Purchase invoice with an item connected to Non-Deductible VAT Posting Setup
+        LibraryPurchase.CreatePurchHeader(
+            PurchHeader, PurchHeader."Document Type"::Invoice,
+            LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        LibraryPurchase.CreatePurchaseLine(
+            PurchLine, PurchHeader, PurchLine.Type::Item,
+            LibraryInventory.CreateItemWithVATProdPostingGroup(VATPostingSetup."VAT Prod. Posting Group"), LibraryRandom.RandInt(100));
+
+        // [GIVEN] Direct Unit Cost is set to a non-zero value
+        PurchLine.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        PurchLine.Modify(true);
+
+        // [GIVEN] Non-Deductible VAT Base and Amount are populated
+        Assert.AreNotEqual(0, PurchLine."Non-Deductible VAT Base", 'Non-Deductible VAT Base should be non-zero before test');
+        Assert.AreNotEqual(0, PurchLine."Non-Deductible VAT Amount", 'Non-Deductible VAT Amount should be non-zero before test');
+
+        // [WHEN] Direct Unit Cost is changed to 0
+        PurchLine.Validate("Direct Unit Cost", 0);
+
+        // [THEN] Non-Deductible VAT Base is cleared
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Base", 'Non-Deductible VAT Base should be zero after setting Direct Unit Cost to 0');
+
+        // [THEN] Non-Deductible VAT Amount is cleared
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Amount", 'Non-Deductible VAT Amount should be zero after setting Direct Unit Cost to 0');
+
+        // [THEN] Amount and VAT Base Amount are also zero
+        Assert.AreEqual(0, PurchLine.Amount, 'Amount should be zero');
+        Assert.AreEqual(0, PurchLine."VAT Base Amount", 'VAT Base Amount should be zero');
+        Assert.AreEqual(0, PurchLine."Amount Including VAT", 'Amount Including VAT should be zero');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Non-Ded. VAT Unit Cost Zero");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Non-Ded. VAT Unit Cost Zero");
+        LibraryNonDeductibleVAT.EnableNonDeductibleVAT();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"VAT Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Non-Ded. VAT Unit Cost Zero");
+    end;
+}

