+        WhseWorksheetLine: Record "Whse. Worksheet Line";
+        WhsePickRequest: Record "Whse. Pick Request";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        Qty1: Decimal;
+        Qty2: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [SCENARIO] Creating pick from pick worksheet when location has Bin Mandatory = true, Require Pick = false, 
+        // Prod. Consump. Whse. Handling = Warehouse Pick (mandatory), and production order components are reserved.
+        // Bug fix: The fix adds condition for "Prod. Consump. Whse. Handling" = "Warehouse Pick (mandatory)" 
+        // to calculate QtyReservedOnPickShip in CalcQtyAvailToTakeOnWhseWorksheetLine.
+
+        // [GIVEN] Initialize and set up quantities
+        Initialize();
+        Qty1 := 2;
+        Qty2 := 1;
+        TotalQty := Qty1 + Qty2;
+
+        // [GIVEN] Create location with Bin Mandatory = true, Require Pick = false, Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        CreateLocationWithBinMandatoryAndProdConsumpWhsePick(Location, Bin);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Create parent and component items with production BOM
+        CreateItemWithProductionBOM(ParentItem, ComponentItem);
+
+        // [GIVEN] Post positive inventory of component item (total of Qty1 + Qty2 = 3 PCS)
+        CreateAndPostItemJournalLine(ComponentItem."No.", TotalQty, Location.Code, Bin.Code);
+
+        // [GIVEN] Create first Released Production Order for ParentItem, Qty = 2
+        CreateAndRefreshProductionOrder(ProductionOrder1, ParentItem."No.", Qty1, Location.Code);
+
+        // [GIVEN] Create second Released Production Order for ParentItem, Qty = 1
+        CreateAndRefreshProductionOrder(ProductionOrder2, ParentItem."No.", Qty2, Location.Code);
+
+        // [GIVEN] Reserve production order components on both orders
+        FindProdOrderComponent(ProdOrderComponent1, ProductionOrder1);
+        ProdOrderComponent1.AutoReserve();
+
+        FindProdOrderComponent(ProdOrderComponent2, ProductionOrder2);
+        ProdOrderComponent2.AutoReserve();
+
+        // [GIVEN] Get warehouse documents on pick worksheet for both production orders
+        LibraryWarehouse.SelectWhseWorksheetTemplate(WhseWorksheetTemplate, WhseWorksheetTemplate.Type::Pick);
+        LibraryWarehouse.CreateWhseWorksheetName(WhseWorksheetName, WhseWorksheetTemplate.Name, Location.Code);
+
+        WhsePickRequest.SetRange(Status, WhsePickRequest.Status::Released);
+        WhsePickRequest.SetRange("Completely Picked", false);
+        WhsePickRequest.SetRange("Location Code", Location.Code);
+        WhsePickRequest.SetRange("Document Type", WhsePickRequest."Document Type"::Production);
+        LibraryWarehouse.GetOutboundSourceDocuments(WhsePickRequest, WhseWorksheetName, Location.Code);
+
+        // [WHEN] Create pick from pick worksheet
+        WhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetName."Worksheet Template Name");
+        WhseWorksheetLine.SetRange(Name, WhseWorksheetName.Name);
+        WhseWorksheetLine.SetRange("Location Code", Location.Code);
+        WhseWorksheetLine.FindFirst();
+
+        LibraryWarehouse.CreatePickFromPickWorksheet(
+          WhseWorksheetLine, 0, WhseWorksheetName."Worksheet Template Name", WhseWorksheetName.Name, Location.Code, '',
+          0, 0, "Whse. Activity Sorting Method"::None, false, false, false, false, false, false, false);
+
+        // [THEN] Pick lines are created successfully (no availability error)
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Location Code", Location.Code);
+        WarehouseActivityLine.SetRange("Item No.", ComponentItem."No.");
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+
+        // [THEN] The total quantity on Take lines matches the production order component quantity
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.CalcSums(Quantity);
+        Assert.AreEqual(TotalQty, WarehouseActivityLine.Quantity, 'Total quantity on warehouse pick lines should match component requirements');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+        InventorySetup: Record "Inventory Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Pick Wksh Avail Bugfix");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Pick Wksh Avail Bugfix");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+        LibraryInventory.NoSeriesSetup(InventorySetup);
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Pick Wksh Avail Bugfix");
+    end;
+
+    local procedure CreateLocationWithBinMandatoryAndProdConsumpWhsePick(var Location: Record Location; var Bin: Record Bin)
+    begin
+        // Create location with: Bin Mandatory = true, Require Pick = false, Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        // This is the key scenario from the bug: location has no Require Pick but uses Warehouse Pick for production consumption
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location.Validate("Require Pick", false);
+        Location.Validate("Require Shipment", false);
+        Location.Validate("Require Receive", false);
+        Location.Validate("Require Put-away", false);
+        Location."Prod. Consump. Whse. Handling" := Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)";
+        Location.Modify(true);
+
+        // Create a bin for this location
+        LibraryWarehouse.CreateBin(Bin, Location.Code, LibraryUtility.GenerateGUID(), '', '');
+    end;
+
+    local procedure CreateItemWithProductionBOM(var ParentItem: Record Item; var ComponentItem: Record Item)
+    var
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        // Create component item
+        LibraryInventory.CreateItem(ComponentItem);
+
+        // Create parent item
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // Create production BOM with 1 quantity per of component item
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // Assign production BOM to parent item
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10]; BinCode: Code[20])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, LocationCode, BinCode, Quantity);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateAndRefreshProductionOrder(var ProductionOrder: Record "Production Order"; ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10])
+    begin
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ItemNo, Quantity);
+        ProductionOrder.Validate("Location Code", LocationCode);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+    end;
+
+    local procedure FindProdOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; ProductionOrder: Record "Production Order")
+    begin
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.FindFirst();
+    end;
+}

