+
+    [Test]
+    [HandlerFunctions('MessageHandler,WhseSourceCreateDocumentOKHandler')]
+    [Scope('OnPrem')]
+    procedure ModifyingLastTakeLineQtyUpdatesCorrectPlaceLine()
+    var
+        Location: Record Location;
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseActivityLineTake: Record "Warehouse Activity Line";
+        WarehouseActivityLinePlace: Record "Warehouse Activity Line";
+        Bin: array[3] of Record Bin;
+        QtyPerBin: Decimal;
+        NewQty: Decimal;
+        i: Integer;
+    begin
+        // [FEATURE] [Production Order] [Warehouse Pick]
+        // [SCENARIO] When modifying the quantity on the last Take line in a Warehouse Pick for a Production Order,
+        // the corresponding Place line (after the Take line) should be updated, not the first Place line.
+        Initialize();
+
+        // [GIVEN] Location with bins, "Require Pick" disabled and "Prod. Consump. Whse. Handling" = Warehouse Pick (mandatory)
+        CreateLocationNotRequirePick(Location);
+
+        // [GIVEN] Create 3 additional bins for inventory
+        for i := 1 to 3 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, LibraryUtility.GenerateGUID(), '', '');
+
+        // [GIVEN] Create component item with "Allow Whse. Overpick" = true
+        LibraryInventory.CreateItem(ChildItem);
+        ChildItem.Validate("Allow Whse. Overpick", true);
+        ChildItem.Modify(true);
+
+        // [GIVEN] Post inventory of 100 to each of the 3 bins
+        QtyPerBin := 100;
+        for i := 1 to 3 do
+            UpdateItemInventory(ChildItem."No.", Location.Code, Bin[i].Code, QtyPerBin);
+
+        // [GIVEN] Create production BOM with the component item
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ChildItem."No.", 1);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create and refresh a released production order with quantity = 300 (to use all 3 bins)
+        CreateAndRefreshProdOrder(ProductionOrder, ProductionOrder."Source Type"::Item, ParentItem."No.", Location.Code, 300);
+
+        // [GIVEN] Create warehouse pick - this creates Take/Place line pairs for each bin
+        ProductionOrder.CreatePick(UserId, 0, false, false, false);
+
+        // [GIVEN] Find all Take lines ordered by Line No.
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Source No.", ProductionOrder."No.");
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.SetCurrentKey("Line No.");
+        WarehouseActivityLine.FindLast();
+        WarehouseActivityLineTake := WarehouseActivityLine;
+
+        // [GIVEN] Find the Place line that corresponds to this Take line (should be the next line by Line No.)
+        WarehouseActivityLinePlace.SetRange("Activity Type", WarehouseActivityLineTake."Activity Type");
+        WarehouseActivityLinePlace.SetRange("No.", WarehouseActivityLineTake."No.");
+        WarehouseActivityLinePlace.SetRange("Action Type", WarehouseActivityLinePlace."Action Type"::Place);
+        WarehouseActivityLinePlace.SetFilter("Line No.", '>%1', WarehouseActivityLineTake."Line No.");
+        WarehouseActivityLinePlace.FindFirst();
+
+        // Store the original quantity of the Place line for the last Take
+        Assert.AreEqual(QtyPerBin, WarehouseActivityLinePlace.Quantity, 'Place line should have same quantity as Take line');
+
+        // [WHEN] Modify the quantity on the last Take line
+        NewQty := 50;
+        WarehouseActivityLineTake.Validate(Quantity, NewQty);
+        WarehouseActivityLineTake.Modify(true);
+
+        // [THEN] The corresponding Place line (after the Take line) should be updated to the new quantity
+        WarehouseActivityLinePlace.Find();
+        Assert.AreEqual(NewQty, WarehouseActivityLinePlace.Quantity, 'The corresponding Place line quantity should be updated');
+
+        // [THEN] Verify that other Place lines still have the original quantity
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityLineTake."No.");
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetFilter("Line No.", '<%1', WarehouseActivityLineTake."Line No.");
+        if WarehouseActivityLine.FindSet() then
+            repeat
+                Assert.AreEqual(QtyPerBin, WarehouseActivityLine.Quantity, 'Other Place lines should not be modified');
+            until WarehouseActivityLine.Next() = 0;
+    end;
 }

