+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyFields()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        SalesHeader: Record "Sales Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        OrderId: BigInteger;
+        OrderNo: Code[50];
+        RefundId: BigInteger;
+        PostedDocNo: Code[20];
+    begin
+        // [SCENARIO] When copying a posted sales invoice to a new sales invoice,
+        // Shopify Order Id, Order No, and Refund Id fields should be cleared
+
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No, and Refund Id set
+        Initialize();
+        OrderId := Any.IntegerInRange(10000, 99999);
+        OrderNo := CopyStr(Any.AlphanumericText(10), 1, MaxStrLen(OrderNo));
+        RefundId := Any.IntegerInRange(10000, 99999);
+        CreateItem(Item, Any.IntegerInRange(100, 999));
+        LibrarySales.CreateCustomer(Customer);
+        PostedDocNo := CreateAndPostSalesInvoiceWithShopifyFields(Item, Customer, OrderId, OrderNo, RefundId);
+        SalesInvoiceHeader.Get(PostedDocNo);
+
+        // Verify the posted invoice has Shopify fields set
+        LibraryAssert.AreEqual(OrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shpfy Order Id');
+        LibraryAssert.AreEqual(OrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shpfy Order No.');
+
+        // [WHEN] Copy the posted invoice to a new sales invoice with Include Header = true
+        SalesHeader.Init();
+        SalesHeader.Validate("Document Type", SalesHeader."Document Type"::Invoice);
+        SalesHeader.Insert(true);
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedDocNo, SalesHeader);
+
+        // [THEN] The new sales header should have Shopify fields cleared
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared on copied document');
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared on copied document');
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared on copied document');
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        IsInitialized := true;
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyFields(Item: Record Item; Customer: Record Customer; OrderId: BigInteger; OrderNo: Code[50]; RefundId: BigInteger): Code[20]
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader."Shpfy Order Id" := OrderId;
+        SalesHeader."Shpfy Order No." := OrderNo;
+        SalesHeader."Shpfy Refund Id" := RefundId;
+        SalesHeader.Modify();
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+        exit(LibrarySales.PostSalesDocument(SalesHeader, true, true));
+    end;
+
+    local procedure CreateItem(var Item: Record Item; Amount: Decimal)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", Amount);
+        Item.Validate("Last Direct Cost", Amount);
+        Item.Modify(true);
+    end;
+}

