diff --git a/App/Layers/W1/Tests/SCM/SCMInvtPickFEFORounding.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInvtPickFEFORounding.Codeunit.al
new file mode 100644
index 00000000..6ccf9afe
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMInvtPickFEFORounding.Codeunit.al
@@ -0,0 +1,185 @@
+codeunit 137932 "SCM Invt. Pick FEFO Rounding"
+{
+    // Tests for inventory pick rounding fix with FEFO and multiple lots
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Inventory Pick] [FEFO] [Rounding]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure InvtPickFEFOMultipleLotsBinsNoRoundingError()
+    var
+        Location: Record Location;
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        BaseItemUnitOfMeasure: Record "Item Unit of Measure";
+        UnitOfMeasure: Record "Unit of Measure";
+        Bin: array[3] of Record Bin;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        LotNo: array[6] of Code[50];
+        ExpirationDate: array[6] of Date;
+        QtyPerUOM: Decimal;
+        SalesQty: Decimal;
+        TotalPickQty: Decimal;
+        i: Integer;
+    begin
+        // [FEATURE] [Inventory Pick] [FEFO] [Rounding] [Item Tracking]
+        // [SCENARIO 123456] Creating inventory pick with FEFO enabled and multiple lots across different bins
+        // should not result in rounding errors leaving unpicked quantity.
+        Initialize();
+
+        // [GIVEN] Location with "Require Pick" = true and "Pick According to FEFO" = true
+        CreateLocationWithFEFO(Location);
+
+        // [GIVEN] Create 3 bins
+        for i := 1 to 3 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, 'S-03-000' + Format(i), '', '');
+
+        // [GIVEN] Item with lot tracking and expiration date required
+        CreateTrackedItemWithExpirationDate(Item);
+
+        // [GIVEN] Create Sales Unit of Measure (PACK) with Qty. per Unit of Measure = 2.888 (causes rounding issues)
+        QtyPerUOM := 2.888;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] Set quantity rounding precision on base unit of measure
+        BaseItemUnitOfMeasure.Get(Item."No.", Item."Base Unit of Measure");
+        BaseItemUnitOfMeasure.Validate("Qty. Rounding Precision", 0.00001);
+        BaseItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create lot numbers with different expiration dates
+        // Expiration dates ordered for FEFO: LOT04 < LOT05 < LOT02 (first) < LOT03/LOT06 < LOT01/LOT02 (second)
+        LotNo[1] := 'LOT01';
+        LotNo[2] := 'LOT02';
+        LotNo[3] := 'LOT03';
+        LotNo[4] := 'LOT04';
+        LotNo[5] := 'LOT05';
+        LotNo[6] := 'LOT06';
+
+        ExpirationDate[1] := CalcDate('<+10M>', WorkDate()); // LOT01 - latest
+        ExpirationDate[2] := CalcDate('<+5M>', WorkDate());  // LOT02 - middle (two records with different dates)
+        ExpirationDate[3] := CalcDate('<+6M>', WorkDate());  // LOT03 - middle
+        ExpirationDate[4] := CalcDate('<+1M>', WorkDate());  // LOT04 - earliest
+        ExpirationDate[5] := CalcDate('<+2M>', WorkDate());  // LOT05 - second earliest
+        ExpirationDate[6] := CalcDate('<+6M>', WorkDate());  // LOT06 - same as LOT03
+
+        // [GIVEN] Post inventory with multiple lots across different bins (mimics the repro data)
+        // Bin 1: LOT01 (434.97616), LOT03 (17.3126), LOT06 (17.0373)
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 434.97616, LotNo[1], ExpirationDate[1]);
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 17.3126, LotNo[3], ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 17.0373, LotNo[6], ExpirationDate[6]);
+
+        // Bin 2: LOT01 (4.13394), LOT02 (4.34355), LOT03 (151.33333), LOT04 (40.01221)
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 4.13394, LotNo[1], CalcDate('<+6M>', WorkDate()));
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 4.34355, LotNo[2], ExpirationDate[2]);
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 151.33333, LotNo[3], ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 40.01221, LotNo[4], ExpirationDate[4]);
+
+        // Bin 3: LOT02 (1.78787), LOT03 (42.73313), LOT05 (4.013)
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 1.78787, LotNo[2], CalcDate('<+1M>', WorkDate()));
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 42.73313, LotNo[3], ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 4.013, LotNo[5], ExpirationDate[5]);
+
+        // [GIVEN] Create a sales order with quantity that causes rounding issues (248 PACK)
+        SalesQty := 248;
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQty);
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [WHEN] Release sales order and create inventory pick
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+        LibraryWarehouse.CreateInvtPutPickMovement(
+            WarehouseActivityHeader."Source Document"::"Sales Order", SalesHeader."No.", false, true, false);
+
+        // [THEN] The total pick quantity should equal the sales order quantity (no rounding error)
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.SetRange("Source Type", Database::"Sales Line");
+        WarehouseActivityLine.SetRange("Source No.", SalesHeader."No.");
+        WarehouseActivityLine.CalcSums(Quantity);
+        TotalPickQty := WarehouseActivityLine.Quantity;
+
+        // [THEN] Verify the total pick quantity equals the sales order quantity
+        Assert.AreEqual(SalesQty, TotalPickQty, 'Total pick quantity should equal sales order quantity without rounding errors');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+    end;
+
+    local procedure CreateLocationWithFEFO(var Location: Record Location)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        Location.Validate("Pick According to FEFO", true);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+    end;
+
+    local procedure CreateTrackedItemWithExpirationDate(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+    begin
+        LibraryItemTracking.CreateItemTrackingCodeWithExpirationDate(ItemTrackingCode, false, true);
+        ItemTrackingCode.Validate("Man. Expir. Date Entry Reqd.", true);
+        ItemTrackingCode.Modify(true);
+        LibraryInventory.CreateTrackedItem(Item, LibraryUtility.GetGlobalNoSeriesCode(), '', ItemTrackingCode.Code);
+    end;
+
+    local procedure PostItemJournalLineWithLotAndExpiration(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Qty: Decimal; LotNo: Code[50]; ExpirationDate: Date)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, LocationCode, BinCode, Qty);
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, Qty);
+        ReservationEntry.Validate("Expiration Date", ExpirationDate);
+        ReservationEntry.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Handle messages during test execution
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al
