--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al
@@ -0,0 +1,152 @@
+codeunit 137099 "SCM Planning Multi Subassembly"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Production Order] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryPlanning: Codeunit "Library - Planning";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PlanningForItemConsumedInMultipleSubassembliesDoesNotSuggestUnnecessaryChanges()
+    var
+        Item1: Record Item;
+        Item2A: Record Item;
+        Item2B: Record Item;
+        Item3: Record Item;
+        ProductionBOMHeader1: Record "Production BOM Header";
+        ProductionBOMHeader2A: Record "Production BOM Header";
+        ProductionBOMHeader2B: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+        EndDate: Date;
+    begin
+        // [SCENARIO] For an item consumed in multiple subassemblies, running planning worksheet should not
+        // suggest unnecessary changes when demand equals supply.
+        // Related to: Item consumed in multiple subassemblies causing incorrect planning suggestions
+        Initialize();
+
+        // [GIVEN] Create four items with Replenishment = Prod Order, Manufacturing Policy = Make-to-Order, Reordering Policy = Lot-for-Lot
+        // Item3 is a component item used in both Item2A and Item2B
+        CreateMakeToOrderLotForLotItem(Item3);
+
+        // [GIVEN] Item2A uses Item3 as component (BOM: Item2A -> Item3)
+        CreateMakeToOrderLotForLotItem(Item2A);
+        CreateCertifiedProductionBOM(ProductionBOMHeader2A, Item3."No.", Item2A."Base Unit of Measure", 1);
+        UpdateItemProductionBOMNo(Item2A, ProductionBOMHeader2A."No.");
+
+        // [GIVEN] Item2B also uses Item3 as component (BOM: Item2B -> Item3)
+        CreateMakeToOrderLotForLotItem(Item2B);
+        CreateCertifiedProductionBOM(ProductionBOMHeader2B, Item3."No.", Item2B."Base Unit of Measure", 1);
+        UpdateItemProductionBOMNo(Item2B, ProductionBOMHeader2B."No.");
+
+        // [GIVEN] Item1 uses both Item2A and Item2B as components (BOM: Item1 -> Item2A + Item2B)
+        CreateMakeToOrderLotForLotItem(Item1);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader1, Item1."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2A."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2B."No.", 1);
+        ProductionBOMHeader1.Validate(Status, ProductionBOMHeader1.Status::Certified);
+        ProductionBOMHeader1.Modify(true);
+        UpdateItemProductionBOMNo(Item1, ProductionBOMHeader1."No.");
+
+        // [GIVEN] Calculate Low Level Code for the BOM structure
+        LibraryPlanning.CalculateLowLevelCode();
+
+        // [GIVEN] Create and refresh Released Production Order for Item1 with Quantity = 1
+        // After refresh, Item3 will have a total demand of 2 (used in both Item2A and Item2B)
+        // and a corresponding supply of 2 on a single Prod. Order Line
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, Item1."No.", 1);
+
+        // [WHEN] Calculate Regenerative Plan for Item3
+        Item3.SetRange("No.", Item3."No.");
+        EndDate := CalcDate('<+30D>', WorkDate());
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item3, WorkDate(), EndDate);
+
+        // [THEN] No requisition lines should be created for Item3 because:
+        // - Total Demand (from Prod. Order Components) = 2 (1 from Item2A + 1 from Item2B)
+        // - Total Supply (from Prod. Order Line) = 2
+        // - Demand equals Supply, so no action is needed
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item3."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty(), 'Planning should not suggest any lines for Item3 when demand equals supply.');
+    end;
+
+    local procedure Initialize()
+    var
+        UntrackedPlanningElement: Record "Untracked Planning Element";
+        RequisitionLine: Record "Requisition Line";
+        ReservationEntry: Record "Reservation Entry";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+        UntrackedPlanningElement.DeleteAll();
+        RequisitionLine.DeleteAll();
+        ReservationEntry.DeleteAll();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        ManufacturingSetup: Record "Manufacturing Setup";
+        LibraryUtility: Codeunit "Library - Utility";
+    begin
+        ManufacturingSetup.Get();
+        ManufacturingSetup.Validate("Released Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        ManufacturingSetup.Validate("Firm Planned Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        ManufacturingSetup.Validate("Planned Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        ManufacturingSetup.Validate("Production BOM Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        ManufacturingSetup.Modify(true);
+    end;
+
+    local procedure CreateMakeToOrderLotForLotItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Manufacturing Policy", Item."Manufacturing Policy"::"Make-to-Order");
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateCertifiedProductionBOM(var ProductionBOMHeader: Record "Production BOM Header"; ItemNo: Code[20]; UnitOfMeasure: Code[10]; QtyPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, UnitOfMeasure);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ItemNo, QtyPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+    end;
+
+    local procedure UpdateItemProductionBOMNo(var Item: Record Item; ProductionBOMNo: Code[20])
+    begin
+        Item.Validate("Production BOM No.", ProductionBOMNo);
+        Item.Modify(true);
+    end;
+}

