+    procedure ExchRateAdjmtWithNoVATEntriesNoDivideByZero()
+    var
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        GLAccount: Record "G/L Account";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        VATEntry: Record "VAT Entry";
+        DocumentNo: Code[20];
+    begin
+        // [SCENARIO] Exchange Rate Adjustment does not fail with divide by zero error when VAT Entry table is empty
+        // [GIVEN] A currency with exchange rate is set as Additional Reporting Currency
+        // [GIVEN] VAT Exchange Rate Adjustment is set to "Adjust Additional-Currency Amount"
+        // [GIVEN] No VAT entries exist in the system
+        // [WHEN] Run Exchange Rate Adjustment with Adjust G/L Accounts enabled
+        // [THEN] No divide by zero error occurs
+
+        // Setup
+        Initialize();
+        CreateCurrencyWithExchangeRate(CurrencyExchangeRate);
+        LibraryERM.SetAddReportingCurrency(CurrencyExchangeRate."Currency Code");
+
+        // Set VAT Exchange Rate Adjustment to trigger VAT adjustment
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup."VAT Exchange Rate Adjustment" := GeneralLedgerSetup."VAT Exchange Rate Adjustment"::"Adjust Additional-Currency Amount";
+        GeneralLedgerSetup.Modify(true);
+
+        // Ensure no VAT entries exist
+        VATEntry.DeleteAll();
+
+        // Create a GL entry to have something to adjust
+        CreateGLEntryForAccount(
+          GLAccount, CurrencyExchangeRate."Currency Code", GLAccount."Exchange Rate Adjustment"::"Adjust Additional-Currency Amount",
+          WorkDate());
+        CreateNewExchangeRate(CurrencyExchangeRate);
+
+        // Exercise: Run the report Adjust Exchange Rate (with AdjGLAcc = true)
+        DocumentNo := Format(LibraryRandom.RandInt(100));
+        LibraryERM.RunExchRateAdjustment(
+          CurrencyExchangeRate."Currency Code", WorkDate(), WorkDate(), ExchangeRateAdjmtTxt, WorkDate(), DocumentNo, true);
+
+        // Verify: No error occurred and GL entry was adjusted
+        VerifyGLEntry(DocumentNo, GLAccount."No.");
+    end;
