+
+        // [GIVEN] A production BOM with the component
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A main item with SKU for Prod. Order replenishment
+        LibraryInventory.CreateItem(MainItem);
+        MainItem.Validate("Replenishment System", MainItem."Replenishment System"::"Prod. Order");
