+        GenJnlLine.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GenJnlLine.Modify(true);
+        // [GIVEN] Job Currency Factor is calculated from the job currency exchange rate
+        CurrencyExchangeRate.Get(CurrencyCode, WorkDate());
+        JobCurrencyFactor := CurrencyExchangeRate."Exchange Rate Amount" / CurrencyExchangeRate."Relational Exch. Rate Amount";
+
+        // [WHEN] Run FromGenJnlLineToJnlLine
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
