+codeunit 134961 "Rem. Level Communication Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reminder] [Reminder Level Communication]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure AddTextForLanguageWithNoExistingAttachmentText()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunication: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [SCENARIO] When adding text for a new language on the Reminder Level Communication page,
+        // and there are no existing attachment texts, the operation should complete without error
+        // "A reminder attachment text cannot be created without an ID"
+        Initialize();
+
+        // [GIVEN] A Reminder Terms with a Reminder Level that has no attachment text
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // [GIVEN] The Reminder Level has no attachment text (Reminder Attachment Text is NULL GUID)
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Level should have no attachment text initially');
+
+        // [GIVEN] A language code for the new attachment text
+        LanguageCode := GetLanguageCode();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] Opening the Reminder Level Communication page and invoking "Add text for language..." action
+        ReminderLevelCommunication.OpenEdit();
+        ReminderLevelCommunication.GoToRecord(ReminderLevel);
+        ReminderLevelCommunication."Add New Language".Invoke();
+        ReminderLevelCommunication.Close();
+
+        // [THEN] No error occurred and the Reminder Attachment Text is created
+        ReminderLevel.Get(ReminderLevel."Reminder Terms Code", ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Level should have an attachment text after adding text for language');
+
+        // [THEN] The Reminder Attachment Text record exists with the correct language
+        ReminderAttachmentText.Get(ReminderLevel."Reminder Attachment Text", LanguageCode);
+        Assert.AreEqual(LanguageCode, ReminderAttachmentText."Language Code", 'Attachment text should have the correct language code');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+
+        IsInitialized := true;
+        Commit();
+    end;
+
+    local procedure GetLanguageCode(): Code[10]
+    var
+        Language: Record Language;
+    begin
+        Language.SetFilter(Code, '<>%1', '');
+        if Language.FindFirst() then
+            exit(Language.Code);
+
+        // Create a language if none exists
+        Language.Init();
+        Language.Code := 'ENU';
+        Language.Name := 'English';
+        if Language.Insert() then;
+        exit(Language.Code);
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Always reply No to the confirmation dialogs for creating default attachment/email texts
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage Languages)
+    var
+        LanguageCode: Code[10];
+    begin
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(LanguageCode));
+        Languages.Filter.SetFilter(Code, LanguageCode);
+        Languages.First();
+        Languages.OK().Invoke();
+    end;
+}

