+    local procedure CreatePostTwoGenJnlLinesWithCurrencyAmountLCYRounding(var GenJournalLine: Record "Gen. Journal Line"; AutomaticAccGroupNo: Code[10]): Code[20]
+    var
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        DocumentNo: Code[20];
+        ForeignCurrencyAmount: Decimal;
+    begin
+        // Create currency with exchange rate that causes rounding issues when dividing Amount (LCY) by 2
+        // Using exchange rate 1 EUR = 10.97223 LCY (similar to Swedish Krona vs Euro scenario)
+        // Amount 480 EUR = 5266.6704 LCY, rounded to 5266.67
+        // 50% of 5266.67 = 2633.335, rounds to 2633.34
+        // 2633.34 + 2633.34 = 5266.68 (1 cent more than original)
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.CreateExchRate(CurrencyExchangeRate, Currency.Code, WorkDate());
+        CurrencyExchangeRate.Validate("Exchange Rate Amount", 1);
+        CurrencyExchangeRate.Validate("Adjustment Exch. Rate Amount", 1);
+        CurrencyExchangeRate.Validate("Relational Exch. Rate Amount", 10.97223);
+        CurrencyExchangeRate.Validate("Relational Adjmt Exch Rate Amt", 10.97223);
+        CurrencyExchangeRate.Modify(true);
+
+        ForeignCurrencyAmount := 480;
+
+        LibraryJournals.CreateGenJournalLineWithBatch(
+          GenJournalLine, GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(),
+          ForeignCurrencyAmount);
+        GenJournalLine.Validate("Bal. Account No.", '');
+        GenJournalLine.Validate("Currency Code", Currency.Code);
+        GenJournalLine.Validate("Automatic Account Group", AutomaticAccGroupNo);
+        GenJournalLine.Modify();
+        DocumentNo := GenJournalLine."Document No.";
+
+        LibraryERM.CreateGeneralJnlLine(
+          GenJournalLine, GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name",
+          GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(), -ForeignCurrencyAmount);
+        GenJournalLine.Validate("Document No.", DocumentNo);
+        GenJournalLine.Validate("Currency Code", Currency.Code);
+        GenJournalLine.Modify();
+
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+        exit(DocumentNo);
+    end;
