+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerWithPartialQtyAndUOMQtyRoundingPrecision()
+    var
+        ComponentItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QtyPerBOM: Decimal;
+    begin
+        // [SCENARIO] When Component Item UOM has 'Qty. Rounding Precision' = 1 and BOM 'Quantity Per' < 1,
+        // the Production Order Component should still have the correct 'Quantity per' value, not 0.
+
+        // [GIVEN] Initialize test
+        Initialize();
+        QtyPerBOM := 0.09;
+
+        // [GIVEN] Create Component Item with Replenishment System = Purchase
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Set Component Item's Base UOM 'Qty. Rounding Precision' = 1
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create FG Item with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Rounding Precision", 1);
+        FGItem.Modify(true);
+
+        // [GIVEN] Create certified Production BOM with Component Item, Quantity Per = 0.09 (partial quantity < 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FGItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPerBOM);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to FG Item
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [GIVEN] Create Sales Order for FG Item with Quantity = 1
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, FGItem."No.", 1);
+
+        // [WHEN] Create Released Production Order from Sales Order
+        LibraryManufacturing.CreateProductionOrderFromSalesOrder(
+            SalesHeader, ProductionOrder.Status::Released, "Create Production Order Type"::ItemOrder);
+
+        // [THEN] Find the created Production Order and its Component
+        FindProductionOrderLine(ProdOrderLine, FGItem."No.");
+        ProductionOrder.Get(ProdOrderLine.Status, ProdOrderLine."Prod. Order No.");
+
+        FindProductionOrderComponent(ProdOrderComponent, ProductionOrder."No.", ComponentItem."No.");
+
+        // [THEN] Verify Production Order Component 'Quantity per' = 0.09 (not 0)
+        Assert.AreEqual(
+            QtyPerBOM, ProdOrderComponent."Quantity per",
+            'Prod. Order Component "Quantity per" should equal BOM Quantity per when Component UOM has Qty. Rounding Precision = 1');
+
+        // [THEN] Verify Expected Quantity = Quantity per * Prod Order Qty = 0.09 * 1 = 0.09
+        Assert.AreEqual(
+            QtyPerBOM, ProdOrderComponent."Expected Quantity",
+            'Prod. Order Component "Expected Quantity" should not be 0');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Prod. Order Qty Rounding");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Prod. Order Qty Rounding");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Prod. Order Qty Rounding");
+    end;
+
+    local procedure FindProductionOrderLine(var ProdOrderLine: Record "Prod. Order Line"; ItemNo: Code[20])
+    begin
+        ProdOrderLine.SetRange("Item No.", ItemNo);
+        ProdOrderLine.FindFirst();
+    end;
+
+    local procedure FindProductionOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; ProdOrderNo: Code[20]; ItemNo: Code[20])
+    begin
+        ProdOrderComponent.SetRange("Prod. Order No.", ProdOrderNo);
+        ProdOrderComponent.SetRange("Item No.", ItemNo);
+        ProdOrderComponent.FindFirst();
+    end;
+
