@@ -0,0 +1,77 @@
+codeunit 148186 "Sustainability Calc. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySustainability: Codeunit "Library - Sustainability";
+
+    [Test]
+    procedure GetCollectableGLAmountReturnsPositiveValueForNegativeGLEntries()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        NegativeAmount: Decimal;
+        CollectedAmount: Decimal;
+        EntryNo: Integer;
+    begin
+        // [SCENARIO] GetCollectableGLAmount should return positive value when G/L entries have negative amount
+        // [FEATURE] Collect Amount from G/L Entries - Sustainability Journal
+
+        // [GIVEN] Clean up before testing
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account for testing
+        GLAccount.Init();
+        GLAccount."No." := 'SUST-TEST-GL';
+        GLAccount.Name := 'Sustainability Test GL Account';
+        GLAccount."Account Type" := GLAccount."Account Type"::Posting;
+        GLAccount.Insert(true);
+
+        // [GIVEN] A Sustainability Account Category with G/L Account Filter configured
+        SustainAccountCategory := LibrarySustainability.InsertAccountCategory(
+            'SUST-CALC-TEST',
+            'Test Category for Calculation',
+            Enum::"Emission Scope"::"Scope 3",
+            Enum::"Calculation Foundation"::Custom,
+            true,
+            false,
+            false,
+            'Custom Amount',
+            true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Modify(true);
+
+        // [GIVEN] A G/L Entry with a negative amount (simulating expense/cost scenario)
+        NegativeAmount := -52818.18;
+        GLEntry.Reset();
+        if GLEntry.FindLast() then
+            EntryNo := GLEntry."Entry No." + 1
+        else
+            EntryNo := 1;
+
+        GLEntry.Init();
+        GLEntry."Entry No." := EntryNo;
+        GLEntry."G/L Account No." := GLAccount."No.";
+        GLEntry."Posting Date" := WorkDate();
+        GLEntry.Amount := NegativeAmount;
+        GLEntry.Insert();
+
+        // [WHEN] GetCollectableGLAmount is called with the category and date range
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(
+            SustainAccountCategory,
+            WorkDate(),
+            WorkDate());
+
+        // [THEN] The collected amount should be positive (absolute value)
+        Assert.IsTrue(CollectedAmount > 0, 'Collected amount should be positive');
+        Assert.AreEqual(Abs(NegativeAmount), CollectedAmount, 'Collected amount should be the absolute value of the G/L entry amount');
+
+        // Cleanup
+        GLEntry.Delete();
+        GLAccount.Delete();
+    end;
+}

