+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransferShipmentAfterRevaluationHasCorrectCostAmount()
+    var
+        Item: Record Item;
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        InTransitLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        PositiveAdjmtILENo: Integer;
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+        Qty: Decimal;
+        TotalCostAmount: Decimal;
+    begin
+        // [FEATURE] [Transfer] [Order] [Undo Shipment] [Revaluation]
+        // [SCENARIO] After undoing a transfer shipment that was revalued, the item ledger entries should have correct cost amounts
+        // reflecting the revalued cost, resulting in zero total cost for the transfer.
+        Initialize();
+
+        // [GIVEN] An item with Positive Adjustment at location "From" with unit cost 10
+        OriginalUnitCost := 10;
+        RevaluedUnitCost := 12;
+        Qty := 1;
+
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        LibraryInventory.CreateItem(Item);
+        CreateAndPostItemJnlWithCostLocationVariant(
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", Qty, OriginalUnitCost, FromLocation.Code, '');
+
+        // Remember the Positive Adjmt. Item Ledger Entry No.
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+        PositiveAdjmtILENo := ItemLedgerEntry."Entry No.";
+
+        // [GIVEN] A transfer order is created and shipped (from location "From" to location "To")
+        LibraryInventory.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Qty);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] The original positive adjustment item ledger entry is revalued to unit cost 12
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Revaluation);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Revaluation, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", 0);
+        ItemJournalLine.Validate("Value Entry Type", ItemJournalLine."Value Entry Type"::Revaluation);
+        ItemJournalLine.Validate("Applies-to Entry", PositiveAdjmtILENo);
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // [GIVEN] Adjust Cost - Item Entries is run
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the posted transfer shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Adjust Cost - Item Entries is run again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The total cost amount for all item ledger entries related to this transfer should be zero
+        // (The undo shipment entry should reflect the revalued cost, not the original cost)
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Transfer);
+        TotalCostAmount := 0;
+        if ItemLedgerEntry.FindSet() then
+            repeat
+                ItemLedgerEntry.CalcFields("Cost Amount (Actual)");
+                TotalCostAmount += ItemLedgerEntry."Cost Amount (Actual)";
+            until ItemLedgerEntry.Next() = 0;
+
+        Assert.AreEqual(0, TotalCostAmount, 'Total cost amount for transfer entries should be zero after undo shipment with revaluation.');
+    end;
+
