+++ b/App/Layers/W1/Tests/SCM/SCMItemAttributesEmptyValue.Codeunit.al
@@ -0,0 +1,96 @@
+codeunit 137499 "SCM Item Attributes Empty Val"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [SCM] [Item Attribute] [UI]
+    end;
+
+    var
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ItemAttributeValueListSetAttributeOnlyHandler')]
+    procedure EmptyAttributeValueNotCreatedWhenSettingAttributeNameOnly()
+    var
+        Item: Record Item;
+        ItemAttribute: Record "Item Attribute";
+        ItemAttributeValue: Record "Item Attribute Value";
+        ItemCard: TestPage "Item Card";
+        InitialAttributeValueCount: Integer;
+    begin
+        // [FEATURE] [Item Attribute Value List]
+        // [SCENARIO] When setting an attribute name without a value in the Item Attribute Value List page, 
+        // an empty Item Attribute Value should not be created.
+        Initialize();
+
+        // [GIVEN] An item and an item attribute with some predefined values
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemAttribute(ItemAttribute, ItemAttribute.Type::Text, '');
+        
+        // [GIVEN] Count existing Item Attribute Values for this attribute
+        ItemAttributeValue.SetRange("Attribute ID", ItemAttribute.ID);
+        InitialAttributeValueCount := ItemAttributeValue.Count();
+
+        // [WHEN] The user opens the Item Attribute Value Editor, sets the Attribute Name without setting a Value
+        LibraryVariableStorage.Enqueue(ItemAttribute.Name);
+        ItemCard.OpenEdit();
+        ItemCard.GotoRecord(Item);
+        ItemCard.Attributes.Invoke();
+        ItemCard.Close();
+
+        // [THEN] No new empty Item Attribute Value record should be created
+        ItemAttributeValue.Reset();
+        ItemAttributeValue.SetRange("Attribute ID", ItemAttribute.ID);
+        ItemAttributeValue.SetRange(Value, '');
+        Assert.RecordIsEmpty(ItemAttributeValue);
+
+        // [THEN] The count of Item Attribute Values should remain the same
+        ItemAttributeValue.SetRange(Value);
+        Assert.AreEqual(InitialAttributeValueCount, ItemAttributeValue.Count(), 'No new Item Attribute Value should be created when Value is empty');
+    end;
+
+    local procedure Initialize()
+    var
+        ItemAttribute: Record "Item Attribute";
+        ItemAttributeValue: Record "Item Attribute Value";
+        ItemAttributeValueMapping: Record "Item Attribute Value Mapping";
+        LibraryApplicationArea: Codeunit "Library - Application Area";
+        LibraryNotificationMgt: Codeunit "Library - Notification Mgt.";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Item Attributes Empty Val");
+        LibraryApplicationArea.EnableFoundationSetup();
+        ItemAttribute.DeleteAll();
+        ItemAttributeValue.DeleteAll();
+        ItemAttributeValueMapping.DeleteAll();
+        LibraryVariableStorage.Clear();
+        LibraryNotificationMgt.DisableAllNotifications();
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Item Attributes Empty Val");
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Item Attributes Empty Val");
+    end;
+
+    [ModalPageHandler]
+    procedure ItemAttributeValueListSetAttributeOnlyHandler(var ItemAttributeValueEditor: TestPage "Item Attribute Value Editor")
+    var
+        AttributeName: Text;
+    begin
+        // Set only the Attribute Name, leave Value empty (simulating the bug scenario)
+        AttributeName := LibraryVariableStorage.DequeueText();
+        ItemAttributeValueEditor.ItemAttributeValueList.New();
+        ItemAttributeValueEditor.ItemAttributeValueList."Attribute Name".SetValue(AttributeName);
+        // Do not set Value - leave it empty
+        ItemAttributeValueEditor.OK().Invoke();
+    end;
+}

