+        // [GIVEN] Create an item with reordering policy Order.
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Create a purchase order for the item (supply without demand - will generate Cancel action).
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Item."Vendor No.");
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        PurchaseLine.Validate("Expected Receipt Date", WorkDate() + 10);
+        PurchaseLine.Modify(true);
+
+        // [GIVEN] Create a sales order for the item with a future shipment date (demand without supply - will generate New action).
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 10));
