+        // [GIVEN] Calculate regenerative plan - this creates both Cancel (for the PO) and New (for the SO) action messages.
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), WorkDate() + 60);
+
+        // [GIVEN] Verify we have both Cancel and New action message lines.
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        CancelLineNo := RequisitionLine."Line No.";
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        RequisitionLine.FindFirst();
+        NewLineNo := RequisitionLine."Line No.";
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        // [WHEN] Filter on Action Message = Cancel and run Carry Out Action Message.
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionLine."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionLine."Journal Batch Name");
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Commit();
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0); // Make Purch. Orders for New action
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.SetHideDialog(true);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The Cancel line should be processed (deleted from worksheet).
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Line No.", CancelLineNo);
+        Assert.IsTrue(RequisitionLine.IsEmpty, 'The Cancel action line should have been processed and removed.');
+
+        // [THEN] The New line should still exist (not processed because it was filtered out).
+        RequisitionLine.SetRange("Line No.", NewLineNo);
+        Assert.IsFalse(RequisitionLine.IsEmpty, 'The New action line should remain because it was filtered out by Action Message filter.');
+
+        // [THEN] The purchase order should be cancelled.
+        PurchaseLine.SetRange("Document No.", PurchaseHeader."No.");
+        PurchaseLine.SetRange("No.", Item."No.");
+        Assert.IsTrue(PurchaseLine.IsEmpty, 'The purchase order line should have been cancelled.');
+    end;
